function renderMatterFormBankDrafting(content){const matterId=activeMatter?.id;if(!matterId)return;const panel=document.createElement('section');panel.className='form-bank-drafting';panel.innerHTML=`<div class="section-head"><div><span class="pill">Draft from firm knowledge</span><h2>Use a Form Bank form</h2></div><span class="command-console-badge">Unfiled draft only</span></div><p class="muted">Select an analyzed firm form. Atlas will combine that stored form with this case’s canonical name, number, court, jurisdiction, judge, parties, and supported case facts. The result remains an unfiled draft requiring attorney review; Atlas will not send, serve, sign, or file it.</p><form id="matterFormBankDraftForm"><div class="grid"><label>Stored firm form<select id="matterFormBankSelect" required><option value="">Loading forms…</option></select></label><label>Draft title<input id="matterFormBankDraftTitle" required maxlength="240"></label></div><label>Required drafting instructions<textarea id="matterFormBankInstructions" required minlength="5" maxlength="4000" placeholder="State what this case-specific draft should address. Atlas will use placeholders for unsupported substantive facts."></textarea></label><div id="matterFormBankSummary" class="form-bank-analysis">Choose an analyzed form to see its drafting metadata.</div><button id="matterFormBankDraft" class="primary" type="submit" disabled>Prepare unfiled draft</button><p id="matterFormBankStatus" class="muted" role="status">Loading active firm forms…</p><div id="matterFormBankError" class="error"></div></form>`;const uploader=content.querySelector('.matter-document-upload');if(uploader)uploader.after(panel);else content.prepend(panel);byId('matterFormBankDraftForm').addEventListener('submit',event=>void submitMatterFormBankDraft(event,matterId));void loadMatterFormBankSelector(matterId);}
