function renderDocumentExecution(){const matters=pilotObjects.filter(item=>item.dimension==='matter');const matterSelect=byId('documentExecutionMatter');const selected=matterSelect.value;replaceOptions(matterSelect,matters,'All cases',item=>item.id,item=>item.title);matterSelect.options[0].disabled=false;if(selected&&matters.some(item=>item.id===selected))matterSelect.value=selected;const docusign=Boolean(documentExecutionState?.docusignConfigured);const notary=Boolean(documentExecutionState?.virtualNotaryConfigured);byId('docusignStatus').textContent=docusign?'Connected':'Setup required';byId('virtualNotaryStatus').textContent=notary?'Connected':'Provider required';byId('docusignSubmit').disabled=!docusign||!byId('docusignDocumentId').value;byId('virtualNotarySubmit').disabled=!notary||!byId('virtualNotaryDocumentId').value;byId('documentExecutionStatus').textContent=docusign||notary?'Execution provider connected':'Provider setup required';const results=byId('documentExecutionResults');results.replaceChildren();for(const document of executableDocuments){const card=document.createElement('article');card.className='object-card';const matter=workspaceMatter(document.matterId);card.append(casePill(document.mediaType==='application/pdf'?'PDF':'DOCX',matter,'Firm-wide'));const heading=document.createElement('h3');heading.textContent=document.title;const detail=document.createElement('p');detail.className='muted';detail.textContent=`${document.type.replaceAll('_',' ')} · ${Math.ceil(Number(document.size??0)/1024)} KB`;const actions=document.createElement('div');actions.className='suggestions';const sign=document.createElement('button');sign.type='button';sign.textContent='Use for Docusign';sign.disabled=!docusign;sign.addEventListener('click',()=>{selectExecutionDocument(document,'signature');renderDocumentExecution();});const notarize=document.createElement('button');notarize.type='button';notarize.textContent='Use for Virtual Notary';notarize.disabled=!notary;notarize.addEventListener('click',()=>{selectExecutionDocument(document,'notary');renderDocumentExecution();});actions.append(sign,notarize);card.append(heading,detail,actions);results.append(card);}if(!executableDocuments.length)results.innerHTML='<div class="empty">No stored PDF or DOCX matches this search. Upload the document to its case first.</div>';const requests=pilotObjects.filter(item=>['signature_request','notary_request'].includes(item.type)).sort((a,b)=>b.createdAt.localeCompare(a.createdAt));const history=byId('documentExecutionRequests');history.replaceChildren();for(const requestItem of requests){const card=document.createElement('article');card.className='object-card';card.append(casePill(requestItem.type==='signature_request'?'Docusign':'Virtual Notary',workspaceMatter(requestItem.id),'Firm-wide'));const heading=document.createElement('h3');heading.textContent=requestItem.title;const status=document.createElement('p');status.className='muted';status.textContent=`${String(requestItem.state?.status??'pending').replaceAll('_',' ')} · ${requestItem.state?.recipientCount??1} participant${(requestItem.state?.recipientCount??1)===1?'':'s'}`;card.append(heading,status);const launch=safeExternalUrl(requestItem.state?.launchUrl);if(launch&&!['completed','declined','voided'].includes(requestItem.state?.status)){const link=document.createElement('a');link.href=launch;link.target='_blank';link.rel='noopener noreferrer';link.textContent=requestItem.type==='signature_request'?'Open in Docusign':'Open notary session';card.append(link);}if(requestItem.state?.completedDocumentId){const done=document.createElement('button');done.type='button';done.textContent='Open completed case document';done.addEventListener('click',()=>showView('documents'));card.append(done);}history.append(card);}if(!requests.length)history.innerHTML='<div class="empty">No signature or notary requests have been created.</div>';}
async function loadDocumentExecution(){byId('documentExecutionStatus').textContent='Checking providers';const query=byId('documentExecutionSearch').value.trim();const matterId=byId('documentExecutionMatter').value;const params=new URLSearchParams();if(query)params.set('query',query);if(matterId)params.set('matterId',matterId);try{[documentExecutionState,executableDocuments]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/document-execution/status`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/document-execution/documents${params.size?`?${params}`:''}`)]);renderDocumentExecution();}catch(error){byId('documentExecutionStatus').textContent=error.message;}}
async function submitDocusign(){const button=byId('docusignSubmit');button.disabled=true;byId('docusignError').textContent='';const popup=window.open('about:blank','atlas-docusign','popup,width=1100,height=850');if(popup)popup.opener=null;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/document-execution/signatures`,{method:'POST',body:JSON.stringify({provider:'docusign',documentId:byId('docusignDocumentId').value,emailSubject:byId('docusignEmailSubject').value||null,signers:[{name:byId('docusignSignerName').value,email:byId('docusignSignerEmail').value}]})});const launch=safeExternalUrl(result.launchUrl);if(launch&&popup)popup.location=launch;else if(popup)popup.close();byId('docusignError').textContent=launch?'Draft envelope created. Finish field placement and sending in Docusign.':'Draft created, but Docusign returned no safe launch URL.';await loadPilotData();await loadDocumentExecution();}catch(error){if(popup)popup.close();byId('docusignError').textContent=error.message;}finally{button.disabled=!documentExecutionState?.docusignConfigured||!byId('docusignDocumentId').value;}}
async function submitVirtualNotary(){const button=byId('virtualNotarySubmit');button.disabled=true;byId('virtualNotaryError').textContent='';const popup=window.open('about:blank','atlas-virtual-notary','popup,width=1100,height=850');if(popup)popup.opener=null;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/document-execution/notarizations`,{method:'POST',body:JSON.stringify({provider:'docusign_notary',documentId:byId('virtualNotaryDocumentId').value,signer:{name:byId('virtualNotarySignerName').value,email:byId('virtualNotarySignerEmail').value},jurisdiction:byId('virtualNotaryJurisdiction').value,notarialAct:byId('virtualNotaryAct').value})});const launch=safeExternalUrl(result.launchUrl);if(launch&&popup)popup.location=launch;else if(popup)popup.close();byId('virtualNotaryError').textContent=launch?'Secure notary session created with the connected provider.':'Request created, but the provider returned no safe session URL.';await loadPilotData();await loadDocumentExecution();}catch(error){if(popup)popup.close();byId('virtualNotaryError').textContent=error.message;}finally{button.disabled=!documentExecutionState?.virtualNotaryConfigured||!byId('virtualNotaryDocumentId').value;}}
function renderCollection(name){activeCollection=name;const config=collectionConfigs[name];byId('collectionTitle').textContent=config.title;byId('collectionNameLabel').textContent=config.label;byId('newCollectionItem').textContent=name==='documents'?'Upload document':`Add ${config.label.toLowerCase()}`;byId('newCollectionItem').classList.toggle('hidden',Boolean(config.readOnly));byId('collectionForm').classList.add('hidden');byId('collectionFileLabel').classList.toggle('hidden',name!=='documents');byId('collectionFile').required=name==='documents';byId('collectionName').required=name!=='documents';const connectedView=['email','calendar'].includes(name);byId('emailConnection').classList.toggle('hidden',!connectedView);if(connectedView)void loadEmailConnections();const textingView=name==='communications';byId('smsConnection').classList.toggle('hidden',!textingView);if(textingView)void loadSmsAssistant();const documentView=name==='documents';byId('documentExecutionPanel').classList.toggle('hidden',!documentView);if(documentView)void loadDocumentExecution();const matterSelect=byId('collectionMatter');matterSelect.replaceChildren();const prompt=document.createElement('option');prompt.value='';prompt.textContent='Select the required case';prompt.disabled=true;prompt.selected=true;matterSelect.append(prompt);for(const matter of pilotObjects.filter(item=>item.dimension==='matter')){const option=document.createElement('option');option.value=matter.id;option.textContent=matter.title;matterSelect.append(option);}byId('collectionDateLabel').classList.toggle('hidden',!['communications','tasks','deadlines'].includes(name));const list=byId('collectionList');list.replaceChildren();if(name==='tasks'){const items=homeWorkItems();byId('collectionStatus').textContent=`${items.length} open canonical task, case deadline, or pending Atlas task suggestion${items.length===1?'':'s'} for this firm.`;items.forEach(item=>appendWorkQueueItem(list,item,{allowAtlasExecution:true}));if(!items.length)list.innerHTML='<div class="empty">No open tasks, deadlines, or Atlas suggestions.</div>';return;}const items=collectionItems(name);byId('collectionStatus').textContent=config.readOnly?`${items.length} canonical ${config.title.toLowerCase()} item(s) available to this firm.`:`${items.length} ${config.title.toLowerCase()} owned exclusively by this firm and scoped to cases.`;for(const item of items){const card=document.createElement('article');card.className='object-card';const matter=workspaceMatter(item.parentObjectId??item.state?.matterId);const when=item.state?.receivedAt??item.state?.sentAt??item.state?.startsAt??item.state?.start??item.state?.date;const detail=collectionItemDetail(name,item);card.append(casePill('',matter,matterTitleFor(item)));const heading=document.createElement('h3');appendCaseLinkedText(heading,item.title);const description=document.createElement('p');description.className='muted';appendCaseLinkedText(description,`${detail}${when?` · ${new Date(when).toLocaleString()}`:''}`);card.append(heading,description);if(name==='documents'){appendDocumentProvenance(card,item);appendDocumentAnalysis(card,item);}const webLink=name==='calendar'?safeExternalUrl(item.state?.webLink):null;if(webLink){const link=document.createElement('a');link.href=webLink;link.target='_blank';link.rel='noopener noreferrer';link.textContent=`Open in ${emailProviderLabel(item.state?.externalSource?.provider??item.state?.externalCalendar?.provider??'connected calendar')}`;card.append(link);}if(name==='documents'&&String(item.state?.storageRef??'').startsWith('atlas-blob://')){const download=document.createElement('button');download.type='button';download.textContent='Download verified file';download.addEventListener('click',()=>void downloadDocument(item,download));card.append(download);}list.append(card);}if(!items.length)list.innerHTML=`<div class="empty">No ${escape(config.title.toLowerCase())} has been synchronized for this firm.</div>`;}
let connectedCommunicationSelection={email:null,calendar:null};
function connectedMailConnection(){return emailConnections.find(item=>item.status==='connected'&&['microsoft','google'].includes(item.provider))??emailConnections.find(item=>['microsoft','google'].includes(item.provider))??null;}
function providerAppUrl(provider,section){if(provider==='microsoft')return section==='calendar'?'https://outlook.office.com/calendar/':'https://outlook.office.com/mail/';return section==='calendar'?'https://calendar.google.com/':'https://mail.google.com/';}
function providerComposeUrl(draft,contact){const connection=connectedMailConnection();if(!connection)return null;const state=draft?.state??{};const recipient=contact?.email??state.recipients?.[0]??'';const url=new URL(connection.provider==='microsoft'?'https://outlook.office.com/mail/deeplink/compose':'https://mail.google.com/mail/');if(connection.provider==='microsoft'){url.searchParams.set('to',recipient);url.searchParams.set('subject',state.subject??draft?.title??'');url.searchParams.set('body',state.body??'');}else{url.searchParams.set('view','cm');url.searchParams.set('fs','1');url.searchParams.set('to',recipient);url.searchParams.set('su',state.subject??draft?.title??'');url.searchParams.set('body',state.body??'');}return url.href;}
function installConnectedCommunicationWorkspace(){const explanation=byId('emailConnection')?.querySelector('.section-head .muted');if(explanation)explanation.textContent='Connect through the provider’s secure OAuth consent screen. Atlas never asks for or stores the mailbox password. Incoming email is synchronized read-only; outbound email and calendar changes occur only from an attorney-approved Atlas draft or event.';if(byId('connectedCommunicationWorkspace'))return;const panel=document.createElement('section');panel.id='connectedCommunicationWorkspace';panel.className='connected-communication-workspace hidden';byId('collectionList').before(panel);}
function communicationItemDate(item){return item.state?.receivedAt??item.state?.sentAt??item.state?.startsAt??item.state?.start??item.state?.date??item.updatedAt;}
function renderConnectedCommunicationWorkspace(name=activeCollection){installConnectedCommunicationWorkspace();const panel=byId('connectedCommunicationWorkspace');const list=byId('collectionList');const connection=connectedMailConnection();if(!['email','calendar'].includes(name)||!connection){panel.classList.add('hidden');list.classList.remove('hidden');return;}const items=collectionItems(name).sort((a,b)=>String(communicationItemDate(b)??'').localeCompare(String(communicationItemDate(a)??'')));panel.classList.remove('hidden');list.classList.add('hidden');const label=emailProviderLabel(connection.provider);if(name==='email'){const selected=items.find(item=>item.id===connectedCommunicationSelection.email)??items[0]??null;connectedCommunicationSelection.email=selected?.id??null;panel.innerHTML=`<div class="connected-app-toolbar"><div><span class="pill">Connected through Atlas</span><h2>${escape(label)} Mail</h2></div><a class="button-link" href="${escape(providerAppUrl(connection.provider,'email'))}" target="_blank" rel="noopener noreferrer">Open ${escape(label)} app</a></div><div class="connected-mail-shell"><nav aria-label="Mailbox folders"><strong>Favorites</strong><button type="button" class="active">Inbox</button><button type="button">Drafts</button><button type="button">Sent</button><button type="button">Archive</button></nav><section class="connected-message-list" aria-label="Messages">${items.map(item=>`<button type="button" data-connected-message="${escape(item.id)}" class="${item.id===selected?.id?'active':''}"><strong>${escape(item.state?.from??item.state?.sender??item.title)}</strong><span>${escape(item.state?.subject??item.title)}</span><small>${communicationItemDate(item)?escape(new Date(communicationItemDate(item)).toLocaleString()):''}</small></button>`).join('')||'<div class="empty">No synchronized email yet.</div>'}</section><article class="connected-reading-pane">${selected?`<span class="pill">Stored in the firm twin</span><h2>${escape(selected.state?.subject??selected.title)}</h2><p class="muted">From ${escape(selected.state?.from??selected.state?.sender??'Connected mailbox')}</p><div>${escape(selected.state?.bodyText??selected.state?.body??selected.state?.summary??'Open the provider app to view the complete provider message.')}</div>${workspaceMatter(selected.parentObjectId??selected.state?.matterId)?`<button type="button" data-open-connected-case="${escape(workspaceMatter(selected.parentObjectId??selected.state?.matterId).id)}">Open related case</button>`:''}`:'<div class="empty">Select a synchronized message.</div>'}</article></div>`;panel.querySelectorAll('[data-connected-message]').forEach(button=>button.addEventListener('click',()=>{connectedCommunicationSelection.email=button.dataset.connectedMessage;renderConnectedCommunicationWorkspace('email');}));panel.querySelector('[data-open-connected-case]')?.addEventListener('click',event=>{const matter=pilotObjects.find(item=>item.id===event.currentTarget.dataset.openConnectedCase);if(matter)openMatter(matter);});return;}panel.innerHTML=`<div class="connected-app-toolbar"><div><span class="pill">Connected through Atlas</span><h2>${escape(label)} Calendar</h2></div><a class="button-link" href="${escape(providerAppUrl(connection.provider,'calendar'))}" target="_blank" rel="noopener noreferrer">Open ${escape(label)} app</a></div><div class="connected-calendar-shell"><aside><strong>Calendars</strong><label><input type="checkbox" checked disabled> Firm calendar</label><label><input type="checkbox" checked disabled> Atlas-approved events</label></aside><section><div class="connected-calendar-heading"><strong>Schedule</strong><span>${escape(new Date().toLocaleDateString(undefined,{month:'long',year:'numeric'}))}</span></div><div class="connected-agenda">${items.map(item=>{const matter=workspaceMatter(item.parentObjectId??item.state?.matterId);return`<article><time>${communicationItemDate(item)?escape(new Date(communicationItemDate(item)).toLocaleString()):'Time pending'}</time><div><strong>${escape(item.title)}</strong><span>${escape(item.state?.location??item.state?.eventType??'Calendar event')}</span>${matter?`<button type="button" data-open-connected-case="${escape(matter.id)}">${escape(matter.title)}</button>`:''}</div></article>`;}).join('')||'<div class="empty">No synchronized calendar events yet.</div>'}</div></section></div>`;panel.querySelectorAll('[data-open-connected-case]').forEach(button=>button.addEventListener('click',()=>{const matter=pilotObjects.find(item=>item.id===button.dataset.openConnectedCase);if(matter)openMatter(matter);}));}
const renderCollectionBase=renderCollection;
renderCollection=function(name){if(name==='clients')name='contacts';renderCollectionBase(name);const contactView=name==='contacts';byId('contactDirectoryTools').classList.toggle('hidden',!contactView);for(const id of ['collectionContactTypeLabel','collectionContactEmailLabel','collectionContactPhoneLabel','collectionContactOrganizationLabel'])byId(id).classList.toggle('hidden',!contactView);byId('collectionContactType').required=contactView;if(contactView){byId('viewTitle').textContent='Contacts';byId('newCollectionItem').textContent='Add contact';byId('collectionScopeLabel').childNodes[0].nodeValue='Related case';renderContactDirectory();}else byId('collectionScopeLabel').childNodes[0].nodeValue='Canonical scope';};
