async function loadPilotData(){const [workspace,subscription,objects,actions]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/subscription`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/assistant/actions`)]);pilotObjects=objects;workspaceActions=actions;byId('firmName').textContent=workspace.name;byId('firmRole').textContent=`${subscription.plan} · ${subscription.status} · ${subscription.seatLimit} seats`;const matters=objects.filter((item)=>item.dimension==='matter');const tasks=objects.filter((item)=>item.dimension==='operation'&&item.type==='task'&&item.state?.status!=='completed');const deadlines=objects.filter((item)=>item.type==='deadline'&&item.state?.status!=='completed');byId('matterCount').textContent=String(matters.length);byId('taskCount').textContent=String(tasks.length);byId('deadlineCount').textContent=String(deadlines.length);renderMatters(matters);renderWorkspaceWork();renderHomeWorkQueue();await Promise.all([loadFeed(),loadFirmEvents(),loadConflictAlerts()]);}
const renderCollectionWithConnectedProvider=renderCollection;
renderCollection=function(name){renderCollectionWithConnectedProvider(name);renderConnectedCommunicationWorkspace(name==='clients'?'contacts':name);};
function researchProviderLabel(name){return name==='westlaw'?'Westlaw':name==='lexisnexis'?'LexisNexis':providerDisplayName(name);}
function renderLegalResearch(){const matters=pilotObjects.filter(item=>item.dimension==='matter');for(const id of ['legalResearchMatter','legalResearchChatMatter']){replaceOptions(byId(id),matters,'Firm-wide research',item=>item.id,item=>item.title);byId(id).options[0].disabled=false;}const connected=legalResearchProviders.filter(item=>item.configured);const providerSelect=byId('legalResearchProvider');for(const option of providerSelect.options){if(option.value==='all')option.disabled=connected.length===0;else option.disabled=!legalResearchProviders.some(item=>item.name===option.value&&item.configured);}if(providerSelect.selectedOptions[0]?.disabled)providerSelect.value=connected[0]?.name??'all';byId('legalResearchSubmit').disabled=connected.length===0;byId('legalResearchStatus').textContent=connected.length?`${connected.length} connected`:'API access required';const chatSource=byId('legalResearchChatSource');const publicReady=Boolean(legalResearchCapabilityState?.publicWeb?.configured);const aiReady=Boolean(legalResearchCapabilityState?.aiConfigured);for(const option of chatSource.options){if(option.value==='best_available')option.disabled=!legalResearchCapabilityState?.liveAvailable;else if(option.value==='public_web')option.disabled=!publicReady;else if(option.value==='all_licensed')option.disabled=!connected.length;else option.disabled=!connected.some(item=>item.name===option.value);}if(chatSource.selectedOptions[0]?.disabled)chatSource.value=legalResearchCapabilityState?.liveAvailable?'best_available':publicReady?'public_web':connected[0]?.name??'best_available';byId('legalResearchChatSubmit').disabled=!legalResearchCapabilityState?.liveAvailable;byId('legalResearchChatBadge').textContent=!aiReady?'AI setup required':legalResearchCapabilityState?.liveAvailable?'Live sources ready':'Live source setup required';const providerList=byId('legalResearchProviders');providerList.replaceChildren();const publicCard=document.createElement('article');publicCard.className='object-card';publicCard.innerHTML=`<span class="pill ${publicReady?'provider-ready':'provider-required'}">${publicReady?'Live and cited':'Setup required'}</span><h3>Cited public web</h3><p class="muted">${publicReady?'Current public legal sources are available through the isolated Atlas web-research boundary.':'Enable the server-side web research provider to use current public sources.'}</p>`;providerList.append(publicCard);for(const provider of legalResearchProviders){const card=document.createElement('article');card.className='object-card';const status=document.createElement('span');status.className=`pill ${provider.configured?'provider-ready':'provider-required'}`;status.textContent=provider.configured?'Connected API':'Contracted API required';const heading=document.createElement('h3');heading.textContent=provider.label;const detail=document.createElement('p');detail.className='muted';detail.textContent=provider.configured?'Licensed search and citations are available to this firm.':'Ask the vendor to provision approved API access, then add the issued server credentials to Atlas.';const link=document.createElement('a');link.href=provider.productUrl;link.target='_blank';link.rel='noopener noreferrer';link.textContent=provider.configured?'Provider information':'Request API access';card.append(status,heading,detail,link);providerList.append(card);}const saved=pilotObjects.filter(item=>['legal_research','legal_research_analysis'].includes(item.type)).sort((a,b)=>String(b.state?.searchedAt??b.createdAt).localeCompare(String(a.state?.searchedAt??a.createdAt)));byId('legalResearchCount').textContent=`${saved.length} saved`;const list=byId('legalResearchResults');list.replaceChildren();for(const item of saved){const card=document.createElement('article');card.className='object-card';const providerNames=item.state?.providers??[...new Set((item.state?.citations??[]).map(source=>source.provider).filter(Boolean))];card.append(casePill(providerNames.map(researchProviderLabel).join(' + ')||'Atlas research',workspaceMatter(item.id),'Firm-wide'));const heading=document.createElement('h3');heading.textContent=item.state?.query??item.title;const summary=document.createElement('p');summary.className='muted';summary.textContent=item.state?.summary??'Research saved for attorney review.';const citations=document.createElement('ul');citations.className='research-citations';for(const source of item.state?.citations??[]){const row=document.createElement('li');const url=safeExternalUrl(source.url);if(url){const link=document.createElement('a');link.href=url;link.target='_blank';link.rel='noopener noreferrer';link.textContent=source.citation??source.title;row.append(link);}else row.textContent=source.citation??source.title;const meta=document.createElement('div');meta.className='muted';meta.textContent=[researchProviderLabel(source.provider),source.court,source.date,source.treatment].filter(Boolean).join(' · ');row.append(meta);citations.append(row);}card.append(heading,summary,citations);list.append(card);}if(!saved.length)list.innerHTML='<div class="empty">No live cited research has been saved to the firm twin yet.</div>';}
async function loadLegalResearch(){byId('legalResearchStatus').textContent='Checking providers';byId('legalResearchError').textContent='';try{[legalResearchProviders,legalResearchCapabilityState]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/legal-research/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/legal-research/capabilities`)]);renderLegalResearch();}catch(error){legalResearchCapabilityState=null;byId('legalResearchStatus').textContent='Unavailable';byId('legalResearchChatBadge').textContent='Unavailable';byId('legalResearchError').textContent=error.message;byId('legalResearchChatError').textContent=error.message;}}
async function submitLegalResearch(){const button=byId('legalResearchSubmit');button.disabled=true;byId('legalResearchError').textContent='';byId('legalResearchStatus').textContent='Searching licensed sources…';try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/legal-research/search`,{method:'POST',body:JSON.stringify({query:byId('legalResearchQuery').value,provider:byId('legalResearchProvider').value,matterId:byId('legalResearchMatter').value||null,jurisdiction:byId('legalResearchJurisdiction').value||null,practiceArea:byId('legalResearchPracticeArea').value||null,limit:10})});byId('legalResearchQuery').value='';await loadPilotData();await loadLegalResearch();byId('legalResearchStatus').textContent='Research saved to canonical context';}catch(error){byId('legalResearchError').textContent=error.message;byId('legalResearchStatus').textContent='Research not completed';}finally{button.disabled=legalResearchProviders.every(item=>!item.configured);}}
function appendLegalResearchMessage(role,text,sources=[],actions=[],webSources=[]){const message=document.createElement('article');message.className=`message ${role}`;message.innerHTML=`<header>${role==='atlas'?'Atlas · live legal research':'You'}</header><div></div>`;appendCaseLinkedText(message.querySelector('div'),text);appendSourceLists(message,sources,webSources);if(actions.length){const proposals=document.createElement('div');proposals.className='actions';actions.forEach(action=>proposals.append(renderAction(action)));const openWorkspace=document.createElement('button');openWorkspace.type='button';openWorkspace.className='primary';openWorkspace.textContent='Open prepared work in Workspace';openWorkspace.addEventListener('click',()=>{showView('workspace');byId('workspaceFilter').value=actions.some(action=>action.actionType==='create_document')?'drafts':'all';renderWorkspaceWork();});proposals.append(openWorkspace);message.append(proposals);}byId('legalResearchChatTranscript').append(message);message.scrollIntoView({behavior:'smooth',block:'nearest'});}
async function submitLegalResearchChat(){const prompt=byId('legalResearchChatInput').value.trim();if(!prompt)return;const button=byId('legalResearchChatSubmit');button.disabled=true;byId('legalResearchChatError').textContent='';clearVisibleExchange('legalResearchChatTranscript');appendLegalResearchMessage('user',prompt);byId('legalResearchChatInput').value='';byId('legalResearchChatStatus').textContent='Atlas is researching live sources and checking citations…';try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/legal-research/chat`,{method:'POST',body:JSON.stringify({prompt,sourceMode:byId('legalResearchChatSource').value,matterId:byId('legalResearchChatMatter').value||null,jurisdiction:byId('legalResearchChatJurisdiction').value||null,practiceArea:byId('legalResearchChatPracticeArea').value||null,...(legalResearchConversationId?{conversationId:legalResearchConversationId}:{})})});legalResearchConversationId=result.conversationId;appendLegalResearchMessage('atlas',result.answer,result.sources??[],result.actionProposals??[],result.webSources??[]);const licensed=(result.sources??[]).some(item=>item.sourceType==='licensed_legal_research');const publicWeb=Boolean(result.webSources?.length);byId('legalResearchChatStatus').textContent=licensed&&publicWeb?'Saved with licensed and cited public sources. Attorney validation required.':licensed?'Saved with licensed authority. Check citator treatment before reliance.':'Saved with cited public sources, not licensed citator treatment. Attorney validation required.';await loadPilotData();renderLegalResearch();}catch(error){appendLegalResearchMessage('atlas',`I could not complete live legal research: ${error.message}`);byId('legalResearchChatError').textContent=error.message;byId('legalResearchChatStatus').textContent='No uncited research answer was saved.';}finally{button.disabled=!legalResearchCapabilityState?.liveAvailable;byId('legalResearchChatInput').focus();}}
function showView(name){activeView=name;const collection=Boolean(collectionConfigs[name]);document.querySelectorAll('.nav button').forEach((button)=>button.classList.toggle('active',button.dataset.view===name));byId('accountInfo').classList.toggle('active',name==='account');byId('view-dashboard').classList.toggle('hidden',name!=='dashboard');byId('view-workspace').classList.toggle('hidden',name!=='workspace');byId('view-events').classList.toggle('hidden',name!=='events');byId('view-matters').classList.toggle('hidden',name!=='matters');byId('view-matter').classList.toggle('hidden',name!=='matter');byId('view-legal-research').classList.toggle('hidden',name!=='legal-research');byId('view-collection').classList.toggle('hidden',!collection);byId('view-social').classList.toggle('hidden',name!=='communications');byId('view-accounting').classList.toggle('hidden',name!=='accounting');byId('view-settings').classList.toggle('hidden',name!=='settings');byId('view-account').classList.toggle('hidden',name!=='account');byId('twinDock').classList.toggle('hidden',!shouldShowTwinDock(name));const placeholder=!['dashboard','workspace','events','matters','matter','legal-research','accounting','settings','account'].includes(name)&&!collection;byId('view-placeholder').classList.toggle('hidden',!placeholder);const title=name==='dashboard'?'Home':name==='workspace'?'Workspace':name==='matters'?'Cases':name==='legal-research'?'Legal Research':name==='matter'?(activeMatter?.title??'Case'):name==='account'?'Account Info':name[0].toUpperCase()+name.slice(1);byId('viewTitle').replaceChildren(name==='matter'&&activeMatter?caseLink(activeMatter):document.createTextNode(title));if(name==='workspace')renderWorkspaceWork();if(name==='events')renderFirmEvents();if(name==='legal-research')void loadLegalResearch();if(name==='communications')void loadSocial();if(name==='accounting'){showAccountingPage(activeAccountingPage,false);void loadAccounting();}if(name==='settings'){void loadSettings();void loadSecuritySettings();void loadMigration();}if(name==='account'){showAccountPage(activeAccountPage,false);void loadAccountProfile();}if(collection)renderCollection(name);if(placeholder)byId('placeholderTitle').textContent=`${title} workspace`;}
const showViewBase=showView;
showView=function(name){return showViewBase(name==='clients'?'contacts':name);};
function money(minor,currency='USD'){return new Intl.NumberFormat(undefined,{style:'currency',currency}).format(Number(minor??0)/100);}
function replaceOptions(select,items,placeholder,valueFor,labelFor){select.replaceChildren();const first=document.createElement('option');first.value='';first.textContent=placeholder;first.disabled=true;first.selected=true;select.append(first);for(const item of items){const option=document.createElement('option');option.value=valueFor(item);option.textContent=labelFor(item);select.append(option);}}
function renderAccountingProviders(){const all=accountingProviders??{payments:[],banks:[],financing:[]};const connections=byId('accountingProviderList');connections.replaceChildren();for(const provider of [...all.payments.map(item=>({...item,kind:'Payment processor'})),...all.banks.map(item=>({...item,kind:'Bank data connection'}))]){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(provider.kind)}</span><h3>${escape(provider.name)}</h3><p class="muted">${escape(provider.hostedCheckout?'Hosted, tokenized payment collection':'Secure provider authorization')}</p>`;connections.append(card);}if(!connections.children.length)connections.innerHTML='<div class="empty">No production bank or payment provider is configured yet. Atlas will never ask for bank or card credentials directly.</div>';const finance=byId('financeProviderList');finance.replaceChildren();for(const provider of all.financing){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">External lender</span><h3>${escape(provider.name)}</h3><p class="muted">Client-consented application handoff; Atlas does not underwrite or lend.</p>`;finance.append(card);}if(!finance.children.length)finance.innerHTML='<div class="empty">No legal-fee financing partner is configured. Candidate providers are being evaluated for consented application handoff and status integration.</div>';}
function renderCryptoAccounting(){const providers=accountingProviders?.crypto??[];const accounts=pilotObjects.filter(item=>item.type==='crypto_receiving_account'&&item.state?.status==='active');const requests=pilotObjects.filter(item=>item.type==='crypto_payment_request');const providerSelect=byId('cryptoProvider');providerSelect.replaceChildren();const providerPrompt=document.createElement('option');providerPrompt.value='';providerPrompt.disabled=true;providerPrompt.selected=true;providerPrompt.textContent=providers.length?'Select configured network':'No crypto provider configured';providerSelect.append(providerPrompt);for(const provider of providers){const option=document.createElement('option');option.value=provider.name;option.textContent=`${provider.asset} · ${provider.network}`;providerSelect.append(option);}providerSelect.disabled=!providers.length;byId('cryptoAddress').disabled=!providers.length;byId('cryptoAccountForm').querySelector('button').disabled=!providers.length;replaceOptions(byId('cryptoReceivingAccount'),accounts,'Select receiving address',item=>item.id,item=>`${item.state.asset} · ${item.state.network} · ${item.state.address}`);replaceOptions(byId('cryptoInvoice'),(accountingSummary?.invoices??[]).filter(row=>row.outstandingMinor>0),'Select an unpaid invoice',row=>row.invoice.id,row=>`${row.invoice.title} · ${money(row.outstandingMinor,row.invoice.state.currency)} due`);byId('cryptoReceivingAccount').disabled=!accounts.length;byId('cryptoRequestForm').querySelector('button').disabled=!accounts.length;byId('cryptoServiceStatus').textContent=providers.length?'Provider connected':'Setup required';const accountList=byId('cryptoAccountList');accountList.replaceChildren();for(const account of accounts){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(account.state.asset)} · ${escape(account.state.network)}</span><h3>${escape(account.title)}</h3><p class="muted">${escape(account.state.address)}</p><small>Firm-controlled wallet · Atlas custody: no</small>`;accountList.append(card);}if(!accounts.length)accountList.innerHTML='<div class="empty">No receiving address is connected. Configure an approved blockchain provider in the Atlas deployment, then add the firm’s public wallet address.</div>';const requestList=byId('cryptoRequestList');requestList.replaceChildren();for(const paymentRequest of requests){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(paymentRequest.state.status)} · ${escape(paymentRequest.state.asset)}</span><h3>${escape(paymentRequest.title)}</h3><p>${escape(money(paymentRequest.state.amountMinor,paymentRequest.state.currency))} · ${escape(paymentRequest.state.network)}</p><p class="muted">Pay to ${escape(paymentRequest.state.destinationAddress)}</p><form><label>Blockchain transaction hash<input required autocomplete="off" placeholder="0x…"></label><button class="primary" type="submit">Verify and record payment</button></form><small class="decision"></small>`;card.querySelector('form').addEventListener('submit',async(event)=>{event.preventDefault();const status=card.querySelector('.decision');status.textContent='Checking blockchain confirmations…';try{const confirmed=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/accounting/crypto/confirmations`,{method:'POST',body:JSON.stringify({paymentRequestId:paymentRequest.id,transactionHash:card.querySelector('input').value})});status.textContent=confirmed.status==='confirmed'?'Confirmed and recorded in accounting.':`Pending · ${confirmed.confirmations}/${confirmed.requiredConfirmations} confirmations`;await loadPilotData();await loadAccounting();}catch(error){status.textContent=error.message;}});requestList.append(card);}if(!requests.length)requestList.innerHTML='<div class="empty">No crypto payment request has been created.</div>';}
function renderQuickBooksAccounting(){const provider=accountingCmsProviders.find(item=>item.name==='quickbooks');const connection=accountingCmsConnections.find(item=>item.provider==='quickbooks'&&item.status!=='disconnected');const summary=accountingSummary?.quickBooks??{recordCount:0,receivableMinor:0,paymentsMinor:0,expensesMinor:0,entries:[]};byId('quickBooksStatus').textContent=connection?(connection.status==='connected'?'Connected':'Attention required'):(provider?'Ready to connect':'Setup required');byId('quickBooksConnect').hidden=Boolean(connection);byId('quickBooksConnect').disabled=!provider;byId('quickBooksSync').hidden=!connection;byId('quickBooksDisconnect').hidden=!connection;byId('quickBooksSync').disabled=connection?.status==='error';byId('quickBooksRecords').textContent=String(summary.recordCount);byId('quickBooksReceivable').textContent=money(summary.receivableMinor);byId('quickBooksPayments').textContent=money(summary.paymentsMinor);byId('quickBooksExpenses').textContent=money(summary.expensesMinor);byId('quickBooksLastSync').textContent=connection?.lastSyncedAt?`Last sync ${new Date(connection.lastSyncedAt).toLocaleString()}`:'Not synchronized';const message=byId('quickBooksMessage');message.textContent=provider?(connection?'QuickBooks finances are mirrored read-only. Imported records retain QuickBooks provenance and become available to Atlas intelligence.':'Connect the firm’s QuickBooks company to populate accounts, customers, vendors, invoices, payments, expenses, bills, deposits, credits, and journals.'):'An administrator must configure the Intuit application credentials before this firm can connect QuickBooks.';const list=byId('quickBooksEntryList');list.replaceChildren();for(const entry of summary.entries??[]){const card=document.createElement('article');card.className='object-card';const amount=entry.state.amountMinor??entry.state.balanceMinor;card.innerHTML=`<span class="pill">${escape(String(entry.state.entryType??'record').replaceAll('_',' '))}</span><h3>${escape(entry.title)}</h3><p>${amount===null||amount===undefined?'':escape(money(amount,entry.state.currency))}</p><small>${escape(entry.state.txnDate??entry.state.dueDate??'QuickBooks financial record')} · Read-only source</small>`;list.append(card);}if(!list.children.length)list.innerHTML='<div class="empty">No QuickBooks finances have been imported yet.</div>';}
function renderAccounting(){const summary=accountingSummary;if(!summary)return;byId('accountingBilled').textContent=money(summary.billedMinor,summary.currency);byId('accountingPaid').textContent=money(summary.paidMinor,summary.currency);byId('accountingReceivable').textContent=money(summary.receivableMinor,summary.currency);byId('accountingTrust').textContent=money(summary.trustBalanceMinor,summary.currency);byId('invoiceCount').textContent=`${summary.invoiceCount} invoice${summary.invoiceCount===1?'':'s'}`;const list=byId('invoiceList');list.replaceChildren();for(const row of summary.invoices){const invoice=row.invoice;const matter=workspaceMatter(invoice.parentObjectId??invoice.state?.matterId);const card=document.createElement('article');card.className='object-card';card.append(casePill(invoice.state.status,matter,matterTitleFor(invoice)));const heading=document.createElement('h3');appendCaseLinkedText(heading,invoice.title);const balance=document.createElement('p');balance.textContent=`${money(row.amountMinor,invoice.state.currency)} billed · ${money(row.outstandingMinor,invoice.state.currency)} outstanding`;const detail=document.createElement('small');detail.textContent=`${invoice.state.trustTreatment==='trust'?'Trust deposit':'Operating funds'}${invoice.state.dueAt?` · Due ${new Date(invoice.state.dueAt).toLocaleDateString()}`:''}`;card.append(heading,balance,detail);list.append(card);}if(!summary.invoices.length)list.innerHTML='<div class="empty">No invoices yet. Create the first case-owned invoice above.</div>';const matters=pilotObjects.filter(item=>item.dimension==='matter');replaceOptions(byId('invoiceMatter'),matters,'Select a case',item=>item.id,item=>item.title);replaceOptions(byId('paymentInvoice'),summary.invoices.filter(row=>row.outstandingMinor>0),'Select an unpaid invoice',row=>row.invoice.id,row=>`${row.invoice.title} · ${money(row.outstandingMinor,row.invoice.state.currency)} due`);renderAccountingProviders();renderCryptoAccounting();renderQuickBooksAccounting();renderAccountingSubpages();showAccountingPage(activeAccountingPage,false);byId('accountingStatus').textContent='Accounting entries are canonical firm knowledge. Atlas can reason over balances and events, but payments and lending remain with regulated external providers.';}
function renderHostedCheckout(){const providers=(accountingProviders?.payments??[]).filter(item=>item.hostedCheckout&&item.rails?.some(rail=>['ach','card'].includes(rail)));const unpaid=(accountingSummary?.invoices??[]).filter(row=>row.outstandingMinor>0);replaceOptions(byId('checkoutInvoice'),unpaid,'Select an unpaid invoice',row=>row.invoice.id,row=>`${row.invoice.title} · ${money(row.outstandingMinor,row.invoice.state.currency)} due`);replaceOptions(byId('checkoutProvider'),providers,providers.length?'Select processor':'No payment processor configured',item=>item.name,item=>item.name);byId('checkoutStatus').textContent=providers.length?'Processor connected':'Setup required';byId('checkoutForm').querySelector('button').disabled=!providers.length||!unpaid.length;}
async function loadAccounting(){byId('accountingStatus').textContent='Loading canonical accounting…';try{[accountingSummary,accountingProviders,accountingCmsProviders,accountingCmsConnections]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/accounting/summary`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/accounting/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections`)]);renderAccounting();renderHostedCheckout();}catch(error){byId('accountingStatus').textContent=error.message;}}
function providerDisplayName(name){if(name==='clio')return'Clio';if(name==='mycase')return'MyCase';if(name==='google')return'Google Workspace';if(name==='microsoft')return'Microsoft 365';return String(name).replaceAll('_',' ').replaceAll('-',' ').replace(/\b\w/g,letter=>letter.toUpperCase());}
function renderMigration(){const available=new Set(migrationProviders.map(item=>item.name));const nonLegalProviders=new Set(['google','microsoft','quickbooks']);const connected=new Map(migrationConnections.filter(item=>item.status!=='disconnected'&&!nonLegalProviders.has(item.provider)).map(item=>[item.provider,item]));const providerNames=[...new Set(['clio','mycase',...migrationProviders.map(item=>item.name).filter(name=>!nonLegalProviders.has(name))])];const providers=byId('migrationProviderList');providers.replaceChildren();for(const name of providerNames){const card=document.createElement('article');card.className='object-card';const connection=connected.get(name);card.innerHTML=`<span class="pill">${connection?'Connected':available.has(name)?'Available':'Setup required'}</span><h3>${escape(providerDisplayName(name))}</h3><p class="muted">${connection?'Read-only coexistence is active. Atlas preserves source provenance.':available.has(name)?'Connect through the provider’s secure authorization screen.':'Add this provider’s approved API credentials to the Atlas deployment before connecting.'}</p>`;const button=document.createElement('button');button.type='button';button.textContent=connection?'Sync now':available.has(name)?`Connect ${providerDisplayName(name)}`:'Not configured';button.disabled=!connection&&!available.has(name);button.addEventListener('click',()=>connection?syncMigrationConnection(connection,button):connectMigrationProvider(name,button));card.append(button);providers.append(card);}const connections=byId('migrationConnectionList');connections.replaceChildren();for(const connection of migrationConnections.filter(item=>!nonLegalProviders.has(item.provider))){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(connection.status)}</span><h3>${escape(providerDisplayName(connection.provider))} connection</h3><p class="muted">${connection.lastSyncedAt?`Last synchronized ${escape(new Date(connection.lastSyncedAt).toLocaleString())}`:'Awaiting first synchronization'}</p>`;connections.append(card);}byId('migrationConnectionStatus').textContent=connected.size?`${connected.size} connected`:'No CMS connected';const batches=byId('migrationBatchList');batches.replaceChildren();byId('migrationBatchCount').textContent=`${migrationBatches.length} batch${migrationBatches.length===1?'':'es'}`;for(const batch of migrationBatches){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(batch.state.status)} · ${escape(batch.state.provider)}</span><h3>${escape(batch.title)}</h3><p>${Number(batch.state.created??0)} created · ${Number(batch.state.skipped??0)} already imported · ${(batch.state.errors??[]).length} errors</p><small>${escape(new Date(batch.createdAt).toLocaleString())}</small>`;batches.append(card);}if(!migrationBatches.length)batches.innerHTML='<div class="empty">No uploaded migration has been run for this firm.</div>';}
async function loadMigration(){byId('migrationConnectionStatus').textContent='Loading';try{[migrationProviders,migrationConnections,migrationBatches]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/migration/imports`)]);renderMigration();}catch(error){byId('migrationConnectionStatus').textContent='Unavailable';byId('migrationConnectionMessage').textContent=error.message;}}
async function connectMigrationProvider(provider,button){button.disabled=true;byId('migrationConnectionMessage').textContent=`Opening ${providerDisplayName(provider)} secure authorization…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/${encodeURIComponent(provider)}/authorize`,{method:'POST',body:JSON.stringify({redirectUri:`${window.location.origin}/v1/cms/oauth/callback`})});const authorizationUrl=new URL(result.authorizationUrl);if(authorizationUrl.protocol!=='https:')throw new Error('The provider returned an insecure authorization URL.');const popup=window.open(authorizationUrl.href,'atlas-cms-authorization','popup,width=720,height=820,noopener,noreferrer');if(!popup)throw new Error('Allow the Atlas authorization popup, then try again.');byId('migrationConnectionMessage').textContent=`Complete consent with ${providerDisplayName(provider)}, then return to Atlas.`;}catch(error){byId('migrationConnectionMessage').textContent=error.message;}finally{button.disabled=false;}}
async function syncMigrationConnection(connection,button){button.disabled=true;byId('migrationConnectionMessage').textContent=`Synchronizing ${providerDisplayName(connection.provider)} read-only data…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections/${encodeURIComponent(connection.id)}/sync`,{method:'POST'});byId('migrationConnectionMessage').textContent=`Sync complete: ${result.imported} imported, ${result.updated} updated, ${result.tombstones??0} source archives preserved.`;await loadPilotData();await loadMigration();}catch(error){byId('migrationConnectionMessage').textContent=error.message;}finally{button.disabled=false;}}
function renderMigrationPreview(preview){const output=byId('migrationPreview');output.classList.remove('hidden');output.replaceChildren();const heading=document.createElement('strong');heading.textContent=`${preview.totalRecords} records detected · ${preview.canImport?'Ready to import':'Review required'}`;output.append(heading);for(const dataset of preview.datasets){const row=document.createElement('p');row.textContent=`${dataset.file}: ${dataset.count} ${dataset.kind} record${dataset.count===1?'':'s'}`;output.append(row);}for(const issue of preview.issues){const row=document.createElement('p');row.className=issue.severity==='error'?'error':'muted';row.textContent=`${issue.file}: ${issue.message}`;output.append(row);}byId('runMigrationImport').disabled=!preview.canImport||preview.totalRecords===0;}
async function selectedMigrationPayload(){const files=[...byId('migrationFiles').files];if(!files.length)throw new Error('Select at least one CSV or JSON export file.');const total=files.reduce((sum,file)=>sum+file.size,0);if(total>18_000_000)throw new Error('This preview is larger than 18 MB. Split the export into smaller batches.');return {provider:byId('migrationProvider').value,files:await Promise.all(files.map(async file=>({name:file.name,content:await file.text()})))};}
function showRouteFromHash(){if(!session)return false;const accountingMatch=window.location.hash.match(/^#accounting\/([a-z-]+)$/);if(accountingMatch){activeAccountingPage=Object.hasOwn(accountingPageLabels,accountingMatch[1])?accountingMatch[1]:'dashboard';showView('accounting');return true;}const accountMatch=window.location.hash.match(/^#account\/([a-z-]+)$/);if(accountMatch){activeAccountPage=accountPageNames.has(accountMatch[1])?accountMatch[1]:'profile';showView('account');return true;}return false;}
async function enterWorkspace(){document.body.classList.add('atlas-authenticated');byId('password').value='';byId('newOwnerPassword').value='';byId('workspaceSearch').value='';byId('workspaceFilter').value='all';byId('login').classList.add('hidden');byId('onboarding').classList.add('hidden');byId('home').classList.remove('hidden');applyManageUsersRole(session.workspaceRole);showView('dashboard');persistSession();try{await loadPilotData();showRouteFromHash();}catch(error){if(!error.message.includes('[FIRM_MFA_REQUIRED]'))throw error;showView('settings');byId('mfaMessage').textContent='This firm requires MFA. Complete account protection before opening firm work.';}}
byId('loginForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('loginError').textContent='';const base=byId('apiBase').value.replace(/\/$/,'');try{session={base,workspaceId:null,token:null,refreshToken:null,workspaceRole:null};const mfaCode=byId('loginMfaCode').value.trim();const result=await request('/v1/auth/login',{method:'POST',body:JSON.stringify({email:byId('email').value,password:byId('password').value,...(mfaCode?{mfaCode}:{})})});session.token=result.accessToken;session.refreshToken=result.refreshToken;session.user=result.user;const firms=await request('/v1/me/workspaces');if(!firms.length)throw new Error('Your account is not connected to a firm workspace.');session.workspaceId=firms[0].workspace.id;session.workspaceRole=firms[0].role;byId('workspaceId').value=session.workspaceId;await enterWorkspace();}catch(error){session=null;clearStoredSession();byId('loginError').textContent=error.message;if(error.message.includes('authenticator or recovery code'))byId('loginMfaCode').focus();}});
async function seedDemoCase(){const caseFile=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({dimension:'matter',type:'civil',title:'Morgan v. Lakeside Property Group',state:{caseNumber:'DEMO-2026-CV-101',courtName:'Superior Court of the State of Delaware',courtJurisdiction:'New Castle County',judgeName:'Hon. Avery Rowan (fictional)',clientName:'Taylor Morgan',parties:[{name:'Taylor Morgan',role:'client'},{name:'Lakeside Property Group',role:'opposing party'}],status:'open',ownerName:'Demo Attorney'}})});const common={parentObjectId:caseFile.id,state:{scope:'matter',matterId:caseFile.id,status:'open'}};for(const item of [{dimension:'client',type:'client',title:'Taylor Morgan',state:{role:'client',email:'taylor.morgan@example.test',phone:'(555) 010-2026'}},{dimension:'person',type:'opposing_counsel',title:'Jordan Blake (fictional)',state:{role:'opposing_counsel',email:'jordan.blake@opposing.test',phone:'(555) 010-3030'}},{dimension:'person',type:'judicial_assistant',title:'Avery Chambers (fictional)',state:{role:'judicial_assistant',email:'avery.chambers@court.test',phone:'(555) 010-4040'}},{dimension:'person',type:'expert_witness',title:'Dr. Riley Chen (fictional)',state:{role:'expert_witness',email:'riley.chen@expert.test',phone:'(555) 010-5050'}},{dimension:'person',type:'contact',title:'Morgan Lee, Court Reporter (fictional)',state:{role:'other_contact',email:'morgan.lee@reporter.test',phone:'(555) 010-6060'}},{dimension:'document',type:'document',title:'Initial Complaint',state:{documentType:'complaint',draft:false}},{dimension:'operation',type:'communication',title:'Client intake call',state:{occurredAt:new Date().toISOString(),summary:'Fictional intake call for the Atlas product demo.'}},{dimension:'operation',type:'task',title:'Review discovery plan',state:{date:new Date(Date.now()+2*86_400_000).toISOString(),assignedTo:'Demo Attorney'}},{dimension:'operation',type:'deadline',title:'Discovery responses due',state:{date:new Date(Date.now()+5*86_400_000).toISOString(),deadlineType:'discovery',assignedTo:'Demo Attorney'}}])await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({...common,...item,state:{...common.state,...item.state}})});return caseFile;}
async function createDemoFirm(){const button=byId('showOnboarding');button.disabled=true;byId('loginError').textContent='Opening the fictional Atlas demo firm…';try{session={base:byId('apiBase').value.replace(/\/$/,''),workspaceId:null,token:null,refreshToken:null,workspaceRole:null};const local=['127.0.0.1','localhost'].includes(window.location.hostname);const email=local?'demo@atlas.local':`demo-${Date.now()}-${Math.random().toString(16).slice(2)}@atlas.local`;const password='fictional-demo-password-only';let result;let existing=false;if(local){try{result=await request('/v1/auth/login',{method:'POST',body:JSON.stringify({email,password})});existing=true;}catch(error){if(!error.message.includes('[INVALID_CREDENTIALS]'))throw error;}}if(!result)result=await request('/v1/auth/register-firm',{method:'POST',body:JSON.stringify({firmName:'Atlas Demo Law',name:'Demo Attorney',email,password})});session.token=result.accessToken;session.refreshToken=result.refreshToken;session.user=result.user;if(existing){const firms=await request('/v1/me/workspaces');if(!firms.length)throw new Error('The fictional demo account is not connected to its firm.');session.workspaceId=firms[0].workspace.id;session.workspaceRole=firms[0].role;}else{session.workspaceId=result.workspace.id;session.workspaceRole=result.membership?.role??'owner';}byId('workspaceId').value=session.workspaceId;const objects=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`);if(!objects.some(item=>item.dimension==='matter'))await seedDemoCase();byId('loginError').textContent='';await enterWorkspace();}catch(error){session=null;clearStoredSession();byId('loginError').textContent=error.message;}finally{button.disabled=false;}}
byId('showOnboarding').addEventListener('click',createDemoFirm);byId('cancelOnboarding').addEventListener('click',()=>{byId('onboarding').classList.add('hidden');byId('login').classList.remove('hidden');});byId('onboardingForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('onboardingError').textContent='';try{session={base:byId('apiBase').value.replace(/\/$/,''),workspaceId:null,token:null,refreshToken:null,workspaceRole:null};const result=await request('/v1/auth/register-firm',{method:'POST',body:JSON.stringify({firmName:byId('newFirmName').value,name:byId('newOwnerName').value,email:byId('newOwnerEmail').value,password:byId('newOwnerPassword').value})});session.workspaceId=result.workspace.id;session.token=result.accessToken;session.refreshToken=result.refreshToken;session.user=result.user;session.workspaceRole=result.membership?.role??'owner';byId('workspaceId').value=result.workspace.id;await enterWorkspace();}catch(error){session=null;clearStoredSession();byId('onboardingError').textContent=error.message;}});
function renderSmsAssistant(){const state=smsState??{configured:false,providerConfigured:false,configuration:null,drafts:[]};byId('smsConnectionStatus').textContent=state.providerConfigured?'Live provider ready':state.configured?'Local review mode':'Not configured';const configuration=state.configuration?.state;if(configuration){byId('smsAutoAcknowledgement').checked=configuration.autoAcknowledgement!==false;byId('smsAcknowledgement').value=configuration.acknowledgement??'';}const list=byId('smsDraftList');list.replaceChildren();for(const draft of state.drafts??[]){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">Human approval required</span><h3>${escape(draft.title)}</h3><label>Recipient<input value="${escape(draft.state?.to)}" readonly></label><label>Review and edit<textarea maxlength="1600">${escape(draft.state?.body)}</textarea></label>`;const send=document.createElement('button');send.className='primary';send.type='button';send.textContent=state.providerConfigured?'Approve and send text':'Provider required to send';send.disabled=!state.providerConfigured;send.addEventListener('click',()=>approveAndSendSmsDraft(draft,card,send));card.append(send);list.append(card);}if(!list.children.length)list.innerHTML='<div class="empty">No text drafts are awaiting review.</div>';byId('smsStatusMessage').textContent=state.providerConfigured?'Twilio is configured. Every substantive send still requires an authenticated person to approve it.':'Fictional inbound texting works locally. Configure Twilio credentials in the Atlas runtime before any real text can be sent.';}
async function loadSmsAssistant(){if(!session)return;try{smsState=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/communications/sms`);renderSmsAssistant();}catch(error){byId('smsConnectionStatus').textContent='Unavailable';byId('smsStatusMessage').textContent=error.message;}}
async function approveAndSendSmsDraft(draft,card,button){button.disabled=true;byId('smsStatusMessage').textContent='Saving the reviewed draft and sending only after your approval…';try{const edited=card.querySelector('textarea').value.trim();let current=draft;if(edited!==draft.state?.body)current=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects/${encodeURIComponent(draft.id)}`,{method:'PATCH',body:JSON.stringify({version:draft.version,state:{...draft.state,body:edited}})});await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/communications/sms/drafts/${encodeURIComponent(draft.id)}/send`,{method:'POST',body:JSON.stringify({version:current.version,confirm:true})});byId('smsStatusMessage').textContent='The approved text was sent and recorded in canonical Communications.';await loadPilotData();await loadSmsAssistant();renderCollection('communications');}catch(error){byId('smsStatusMessage').textContent=error.message;button.disabled=false;}}
byId('newMatter').addEventListener('click',()=>byId('matterForm').classList.remove('hidden'));byId('cancelMatter').addEventListener('click',()=>byId('matterForm').classList.add('hidden'));byId('matterForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('matterError').textContent='';try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({dimension:'matter',type:byId('matterType').value,title:byId('matterTitle').value,state:{caseNumber:byId('matterCaseNumber').value||null,courtName:byId('matterCourtName').value||null,courtJurisdiction:byId('matterCourtJurisdiction').value||null,judgeName:byId('matterJudgeName').value||null,clientName:byId('matterClientName').value||null,parties:parsedMatterParties(),status:'open'}})});event.target.reset();byId('matterForm').classList.add('hidden');await loadPilotData();}catch(error){byId('matterError').textContent=error.message;}});byId('backToMatters').addEventListener('click',()=>showView('matters'));document.querySelectorAll('[data-matter-tab]').forEach(button=>button.addEventListener('click',()=>renderMatterTab(button.dataset.matterTab)));
function fileAsBase64(file){return new Promise((resolve,reject)=>{const reader=new FileReader();reader.addEventListener('load',()=>resolve(String(reader.result).split(',')[1]??''));reader.addEventListener('error',()=>reject(new Error('The selected file could not be read.')));reader.readAsDataURL(file);});}
async function downloadDocument(item,button){button.disabled=true;const original=button.textContent;button.textContent='Verifying…';try{const response=await fetch(`${session.base}/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects/${encodeURIComponent(item.id)}/content`,{headers:{authorization:`Bearer ${session.token}`}});if(!response.ok){const body=await response.json().catch(()=>({}));throw new Error(body.error?.message??'The file could not be downloaded.');}const blob=await response.blob();const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=item.title;link.click();setTimeout(()=>URL.revokeObjectURL(link.href),0);button.textContent='Downloaded';}catch(error){button.textContent=error.message;}finally{setTimeout(()=>{button.disabled=false;button.textContent=original;},2500);}}
async function monitorDocumentAnalysis(objectId){if(!objectId)return;byId('collectionError').textContent='Uploaded securely. Atlas is now reading, classifying, summarizing, and cataloging the document.';for(let attempt=0;attempt<30;attempt+=1){await new Promise(resolve=>setTimeout(resolve,2000));try{const document=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects/${encodeURIComponent(objectId)}`);const index=pilotObjects.findIndex(item=>item.id===document.id);if(index>=0)pilotObjects[index]=document;else pilotObjects.push(document);if(activeCollection==='documents')renderCollection('documents');if(document.state?.extractionStatus==='completed'){byId('collectionError').textContent=`Atlas cataloged this as ${String(document.state.documentType??'other').replaceAll('_',' ')} and added its summary and extracted findings for review.`;return;}}catch(error){byId('collectionError').textContent=error.message;return;}}byId('collectionError').textContent='The document is stored, but analysis is still pending. Check While You Were Gone for completion or an analysis error.';}
