byId('collectionForm').addEventListener('submit',async(event)=>{
  event.preventDefault();
  const config=collectionConfigs[activeCollection];
  const matterId=byId('collectionMatter').value;
  if(!matterId){byId('collectionError').textContent=activeCollection==='contacts'?'Select the case this contact is connected to.':'Select the case that owns this legal work.';return;}
  byId('collectionError').textContent='';
  try{
    let uploadedDocumentId=null;
    if(activeCollection==='documents'){
      const file=byId('collectionFile').files[0];
      if(!file)throw new Error('Choose a document to upload.');
      byId('collectionError').textContent='Uploading and verifying document…';
      const uploaded=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/files`,{method:'POST',body:JSON.stringify({matterId,filename:file.name,mediaType:file.type||'application/octet-stream',contentBase64:await fileAsBase64(file),documentType:byId('collectionDetails').value||null})});
      uploadedDocumentId=uploaded.root?.id??null;
    }else{
      const contactType=activeCollection==='contacts'?byId('collectionContactType').value:null;
      if(activeCollection==='contacts'&&!contactTypes.has(contactType))throw new Error('Choose a valid contact type.');
      await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({parentObjectId:matterId,dimension:activeCollection==='contacts'&&contactType==='client'?'client':config.dimension,type:contactType??config.type,title:byId('collectionName').value,state:{scope:'matter',matterId,...(activeCollection==='contacts'?{contactType,email:byId('collectionContactEmail').value.trim()||null,phone:byId('collectionContactPhone').value.trim()||null,organization:byId('collectionContactOrganization').value.trim()||null}:{}),details:byId('collectionDetails').value||null,date:byId('collectionDate').value?new Date(byId('collectionDate').value).toISOString():null,status:'open'}})});
    }
    event.target.reset();
    byId('collectionError').textContent='';
    byId('collectionForm').classList.add('hidden');
    await loadPilotData();
    renderCollection(activeCollection);
    if(uploadedDocumentId)void monitorDocumentAnalysis(uploadedDocumentId);
  }catch(error){byId('collectionError').textContent=error.message;}
});
