byId('smsDraftForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('smsStatusMessage').textContent='Creating a reviewable text draft…';try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/communications/sms/drafts`,{method:'POST',body:JSON.stringify({to:byId('smsDraftTo').value,body:byId('smsDraftBody').value})});event.target.reset();byId('smsStatusMessage').textContent='Draft created. It will not be sent without explicit approval.';await loadPilotData();await loadSmsAssistant();}catch(error){byId('smsStatusMessage').textContent=error.message;}});
byId('migrationUploadForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('migrationUploadError').textContent='';byId('runMigrationImport').disabled=true;try{migrationPayload=await selectedMigrationPayload();const preview=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/migration/preview`,{method:'POST',body:JSON.stringify(migrationPayload)});renderMigrationPreview(preview);}catch(error){migrationPayload=null;byId('migrationUploadError').textContent=error.message;}});
byId('runMigrationImport').addEventListener('click',async()=>{if(!migrationPayload)return;const button=byId('runMigrationImport');button.disabled=true;byId('migrationUploadError').textContent='Importing canonical records…';try{const batch=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/migration/imports`,{method:'POST',body:JSON.stringify(migrationPayload)});byId('migrationUploadError').textContent=`Import complete: ${batch.state.created} created, ${batch.state.skipped} already present, ${(batch.state.errors??[]).length} errors.`;migrationPayload=null;byId('migrationUploadForm').reset();byId('migrationPreview').classList.add('hidden');await loadPilotData();await loadMigration();}catch(error){byId('migrationUploadError').textContent=error.message;button.disabled=false;}});
async function connectDemoEmail(provider){const status=byId('emailConnectionStatus');const message=byId('emailConnectionMessage');if(!['127.0.0.1','localhost'].includes(window.location.hostname)){message.textContent='The deployed OAuth connector must be configured before this provider can be authorized.';return;}document.querySelectorAll('[data-email-provider]').forEach(button=>button.disabled=true);status.textContent='Connecting demo';message.textContent='Creating fictional provider data without transmitting credentials…';try{let matter=pilotObjects.find(item=>item.dimension==='matter');if(!matter)matter=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({dimension:'matter',type:'civil',title:'Morgan v. Lakeside',state:{caseNumber:'DEMO-2026-101',clientName:'Taylor Morgan',status:'open'}})});const mailbox=provider==='google'?'demo@atlas-google.test':'demo@atlas-microsoft.test';for(const email of [{id:'status-request',from:'client@example.test',subject:'Request for case status',bodyText:'Please provide an update on the case when available.'},{id:'discovery-extension',from:'counsel@example.test',subject:'Discovery extension request',bodyText:'Please confirm whether your client agrees to a fourteen-day extension.'}])await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/ingestions/email`,{method:'POST',body:JSON.stringify({connector:`demo-${provider}`,externalId:email.id,matterId:matter.id,from:email.from,to:[mailbox],subject:email.subject,bodyText:email.bodyText,attachments:[]})});if(!pilotObjects.some(item=>item.type==='deadline'&&item.state?.externalSource?.provider===`demo-${provider}`))await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({parentObjectId:matter.id,dimension:'operation',type:'deadline',title:'Discovery responses due',state:{scope:'matter',matterId:matter.id,date:new Date(Date.now()+5*86_400_000).toISOString(),status:'open',externalSource:{provider:`demo-${provider}`}}})});await loadPilotData();status.textContent='Demo connected';message.textContent=`Fictional ${provider==='google'?'Google Workspace':'Microsoft 365'} email and calendar data is now cataloged for this firm.`;renderCollection(activeCollection);}catch(error){status.textContent='Not connected';message.textContent=error.message;}finally{document.querySelectorAll('[data-email-provider]').forEach(button=>button.disabled=false);}}
const renderEmailConnectionsWithApprovedSend=renderEmailConnections;
renderEmailConnections=function(){renderEmailConnectionsWithApprovedSend();byId('emailConnections')?.querySelectorAll('.object-card .muted').forEach(paragraph=>{paragraph.textContent=paragraph.textContent.replace('Email is read-only;','Incoming email is read-only; approved Atlas drafts can be sent;').replace('Read-only email and calendar synchronization.','Read-only incoming synchronization; approved Atlas drafts can be sent through the connected mailbox.');});};
const loadEmailConnectionsWithProviderWorkspace=loadEmailConnections;
loadEmailConnections=async function(){await loadEmailConnectionsWithProviderWorkspace();if(['email','calendar'].includes(activeCollection))renderConnectedCommunicationWorkspace(activeCollection);};
function emailProviderLabel(provider){return provider==='google'?'Google Workspace':provider==='microsoft'?'Microsoft 365':provider;}
function liveMailProviderNames(){return new Set(emailProviders.filter(item=>item.capabilities?.resources?.includes('email')&&item.capabilities?.resources?.includes('calendar')).map(item=>item.name));}
function installDiscoveredEmailProviderButtons(){const host=byId('emailConnection').querySelector('.suggestions');for(const provider of liveMailProviderNames()){if(host.querySelector(`[data-email-provider="${CSS.escape(provider)}"]`))continue;const button=document.createElement('button');button.type='button';button.dataset.emailProvider=provider;button.addEventListener('click',()=>connectEmailProvider(provider));host.append(button);}}
function renderEmailConnections(){const list=byId('emailConnections');list.replaceChildren();const supported=liveMailProviderNames();const connections=emailConnections.filter(item=>supported.has(item.provider));byId('emailConnectionStatus').textContent=connections.length?`${connections.length} connected`:'Not connected';for(const connection of connections){const emailCount=pilotObjects.filter(item=>item.type==='incoming_email'&&item.state?.externalSource?.provider===connection.provider).length;const calendarCount=pilotObjects.filter(item=>item.type==='calendar_event'&&item.state?.externalSource?.provider===connection.provider).length;const card=document.createElement('article');card.className='object-card';const provider=emailProviders.find(item=>item.name===connection.provider);const capability=provider?.capabilities?.calendarWriteAfterApproval?'Email is read-only; attorney-approved Atlas events can be added to this calendar.':'Read-only email and calendar synchronization.';card.innerHTML=`<span class="pill">${escape(connection.status)}</span><h3>${escape(emailProviderLabel(connection.provider))}</h3><p class="muted">${escape(capability)} · ${emailCount} emails · ${calendarCount} calendar events${connection.lastSyncedAt?` · Last synced ${escape(new Date(connection.lastSyncedAt).toLocaleString())}`:' · Awaiting first sync'}</p>`;const sync=document.createElement('button');sync.className='primary';sync.textContent='Sync email & calendar';sync.addEventListener('click',()=>syncEmailConnection(connection,sync));const disconnect=document.createElement('button');disconnect.className='danger';disconnect.textContent='Disconnect';disconnect.addEventListener('click',()=>disconnectEmailConnection(connection,disconnect));card.append(sync,document.createTextNode(' '),disconnect);list.append(card);}if(!connections.length)list.innerHTML='<div class="empty">No live mailbox or calendar is connected.</div>';}
async function loadEmailConnections(){if(!session)return;try{[emailProviders,emailConnections]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections`)]);installDiscoveredEmailProviderButtons();renderEmailConnections();const available=liveMailProviderNames();document.querySelectorAll('[data-email-provider]').forEach(button=>{const configured=available.has(button.dataset.emailProvider);button.textContent=`${configured?'Connect':'Preview fictional'} ${emailProviderLabel(button.dataset.emailProvider)}`;});if(emailConnections.some(item=>available.has(item.provider)))byId('emailConnectionMessage').textContent='Connected mail is synchronized read-only, cataloged as canonical firm activity, and routed through Atlas intelligence for attorney review.';}catch(error){byId('emailConnectionStatus').textContent='Unavailable';byId('emailConnectionMessage').textContent=error.message;}}
async function syncEmailConnection(connection,button){button.disabled=true;byId('emailConnectionMessage').textContent=`Synchronizing ${emailProviderLabel(connection.provider)}…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections/${encodeURIComponent(connection.id)}/sync`,{method:'POST'});byId('emailConnectionMessage').textContent=`Sync complete: ${result.imported} imported, ${result.updated} updated, ${result.tombstones??0} archived at the source${result.calendarPublication?.published?`, ${result.calendarPublication.published} approved event(s) added to ${emailProviderLabel(connection.provider)}`:''}.`;await loadPilotData();await loadEmailConnections();if(activeCollection)renderCollection(activeCollection);}catch(error){byId('emailConnectionMessage').textContent=error.message;}finally{button.disabled=false;}}
async function disconnectEmailConnection(connection,button){button.disabled=true;try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections/${encodeURIComponent(connection.id)}`,{method:'DELETE'});byId('emailConnectionMessage').textContent=`${emailProviderLabel(connection.provider)} disconnected. Existing Atlas records were preserved.`;await loadEmailConnections();}catch(error){byId('emailConnectionMessage').textContent=error.message;button.disabled=false;}}
async function connectEmailProvider(provider){const configured=emailProviders.some(item=>item.name===provider);if(!configured)return connectDemoEmail(provider);const buttons=document.querySelectorAll('[data-email-provider]');buttons.forEach(button=>button.disabled=true);byId('emailConnectionStatus').textContent='Authorizing';byId('emailConnectionMessage').textContent=`Opening ${emailProviderLabel(provider)} secure consent. Atlas never receives the mailbox password.`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/${encodeURIComponent(provider)}/authorize`,{method:'POST',body:JSON.stringify({redirectUri:`${window.location.origin}/v1/cms/oauth/callback`})});const authorizationUrl=new URL(result.authorizationUrl);if(authorizationUrl.protocol!=='https:')throw new Error('The provider returned an insecure authorization URL.');const popup=window.open(authorizationUrl.href,'atlas-mailbox-authorization','popup,width=720,height=820');if(!popup)throw new Error('Allow the Atlas authorization popup, then try again.');try{popup.opener=null;}catch{}byId('emailConnectionMessage').textContent=`Finish consent with ${emailProviderLabel(provider)} in the secure provider window. Return here afterward and Atlas will detect the connection.`;}catch(error){byId('emailConnectionStatus').textContent='Not connected';byId('emailConnectionMessage').textContent=error.message;}finally{buttons.forEach(button=>button.disabled=false);}}
document.querySelectorAll('[data-email-provider]').forEach(button=>button.addEventListener('click',()=>connectEmailProvider(button.dataset.emailProvider)));
window.addEventListener('focus',()=>{if(session&&['email','calendar'].includes(activeCollection))void loadEmailConnections();});
window.addEventListener('focus',()=>{if(!session)return;if(activeView==='settings')void loadMigration();if(activeView==='accounting')void loadAccounting();});
function renderFirmSecurity(events,sessions){const eventList=byId('securityEventList');eventList.replaceChildren();for(const event of events.slice(0,20)){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(event.outcome)}</span><h3>${escape(event.type.replaceAll('.',' '))}</h3><p class="muted">${escape(new Date(event.createdAt).toLocaleString())}${event.ipAddress?` · ${escape(event.ipAddress)}`:''}${event.details?.reason?` · ${escape(event.details.reason.replaceAll('_',' '))}`:''}</p>`;eventList.append(card);}if(!eventList.children.length)eventList.innerHTML='<div class="empty">No security activity has been recorded for this firm.</div>';const sessionList=byId('firmSessionList');sessionList.replaceChildren();byId('firmSessionCount').textContent=`${sessions.length} recorded`;for(const firmSession of sessions.slice(0,30)){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(firmSession.status)}${firmSession.current?' · current':''}</span><h3>${escape(firmSession.user?.name??firmSession.user?.email)}</h3><p class="muted">${escape(firmSession.user?.email)} · Started ${escape(new Date(firmSession.createdAt).toLocaleString())}</p>`;sessionList.append(card);}if(!sessionList.children.length)sessionList.innerHTML='<div class="empty">No firm sessions were returned.</div>';}
async function loadSecuritySettings(){if(!session)return;try{const mfa=await request('/v1/auth/mfa');byId('mfaStatus').textContent=mfa.enabled?'MFA enabled':mfa.pending?'Setup pending':'MFA not enabled';byId('mfaEnrollForm').classList.toggle('hidden',mfa.enabled);byId('mfaDisableForm').classList.toggle('hidden',!mfa.enabled);if(mfa.enabled)byId('mfaMessage').textContent=`${mfa.recoveryCodesRemaining} unused recovery code${mfa.recoveryCodesRemaining===1?'':'s'} remain.`;}catch(error){byId('mfaStatus').textContent='Unavailable';byId('mfaMessage').textContent=error.message;}try{const [events,sessions,policy]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/events?limit=100`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/sessions`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/policy`)]);byId('firmSecurityAdmin').classList.remove('hidden');byId('firmMfaRequired').checked=policy.requireMfa;byId('firmMfaPolicyStatus').textContent=policy.requireMfa?'Required':'Optional';renderFirmSecurity(events,sessions);byId('firmSecurityMessage').textContent='Security activity is append-only. Firm administrators can terminate every session during an incident.';}catch(error){byId('firmSecurityAdmin').classList.add('hidden');}}
const managedMemberRoles=[['admin','Administrator'],['attorney','Attorney'],['paralegal','Paralegal'],['billing','Billing'],['member','Staff member'],['viewer','Viewer']];
function memberRoleLabel(role){return managedMemberRoles.find(item=>item[0]===role)?.[1]??(role==='owner'?'Firm owner':role);}
function readableAccountDate(value,fallback='Not recorded'){if(!value)return fallback;const parsed=new Date(value);return Number.isNaN(parsed.valueOf())?fallback:parsed.toLocaleString();}
function canManageFirmMember(member){if(!['owner','admin'].includes(session.workspaceRole))return false;if(member.userId===session.user?.id||member.role==='owner')return false;if(session.workspaceRole==='admin'&&member.role==='admin')return false;return true;}
function renderFirmMembers(members){const list=byId('memberList');list.replaceChildren();const active=members.filter(item=>item.active!==false).length;byId('memberCount').textContent=`${active} active seat${active===1?'':'s'}`;for(const member of members){const security=member.security??{};const mfaEnabled=security.mfaEnabled??member.mfaEnabled??false;const userName=member.user?.name??member.userId;const isSelf=member.userId===session.user?.id;const manageable=canManageFirmMember(member);const card=document.createElement('article');card.className='object-card';const head=document.createElement('div');head.className='manage-users-member-head';head.innerHTML=`<div><span class="pill">${escape(memberRoleLabel(member.role))} · ${member.active===false?'deactivated':'active'}${isSelf?' · you':''}</span><h3>${escape(userName)}</h3><p class="muted">${escape(member.user?.email??'Firm user')}</p></div>`;const status=document.createElement('span');status.className='command-console-badge';status.textContent=mfaEnabled?'MFA protected':'MFA not enabled';head.append(status);const actions=document.createElement('div');actions.className='manage-users-actions';const roleLabel=document.createElement('label');roleLabel.append(document.createTextNode('Firm role'));const roleSelect=document.createElement('select');roleSelect.setAttribute('aria-label',`Firm role for ${userName}`);const roles=session.workspaceRole==='owner'?managedMemberRoles:managedMemberRoles.filter(item=>item[0]!=='admin');if(member.role==='owner'){const ownerOption=document.createElement('option');ownerOption.value='owner';ownerOption.textContent='Firm owner';roleSelect.append(ownerOption);}for(const [value,label] of roles){const option=document.createElement('option');option.value=value;option.textContent=label;roleSelect.append(option);}roleSelect.value=member.role;roleSelect.disabled=!manageable;roleSelect.addEventListener('change',()=>void updateMembershipRole(member,roleSelect.value,roleSelect));roleLabel.append(roleSelect);actions.append(roleLabel);if(manageable){const accessButton=document.createElement('button');accessButton.type='button';accessButton.className=member.active===false?'primary':'danger';accessButton.textContent=member.active===false?'Restore firm access':'Remove firm access';accessButton.addEventListener('click',()=>void setMembershipActive(member,member.active===false,accessButton));actions.append(accessButton);}else{const protectedLabel=document.createElement('span');protectedLabel.className='muted';protectedLabel.textContent=isSelf?'Your own access must be managed by another authorized administrator.':member.role==='owner'?'The firm owner account is protected.':'Only the firm owner can manage another administrator.';actions.append(protectedLabel);}const details=document.createElement('details');details.className='manage-users-details';details.innerHTML=`<summary>View account and firm settings</summary><div class="manage-users-settings"><div class="manage-users-setting"><strong>${escape(member.active===false?'Deactivated':'Active')}</strong><span>Firm access</span></div><div class="manage-users-setting"><strong>${escape(memberRoleLabel(member.role))}</strong><span>Firm permission role</span></div><div class="manage-users-setting"><strong>${mfaEnabled?'Enabled':'Not enabled'}</strong><span>Authenticator MFA</span></div><div class="manage-users-setting"><strong>${escape(String(security.activeSessionCount??0))}</strong><span>Active sessions</span></div><div class="manage-users-setting"><strong>${escape(readableAccountDate(security.lastSessionAt))}</strong><span>Last session</span></div><div class="manage-users-setting"><strong>${escape(readableAccountDate(member.user?.createdAt??member.createdAt))}</strong><span>Account added</span></div></div>${member.deactivationReason?`<p class="muted">Access removal reason: ${escape(member.deactivationReason)}</p>`:''}<p class="muted">Administrators can manage this user’s firm role and access status. Personal authentication secrets and credentials are never available here.</p>`;card.append(head,actions,details);list.append(card);}if(!members.length)list.innerHTML='<div class="empty">No firm users were returned.</div>';}
async function updateMembershipRole(member,role,select){const previous=member.role;const name=member.user?.name??member.userId;if(!window.confirm(`Change ${name}'s firm role from ${memberRoleLabel(previous)} to ${memberRoleLabel(role)}?`)){select.value=previous;return;}select.disabled=true;byId('manageUsersMessage').textContent=`Updating ${name}…`;try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/memberships/${encodeURIComponent(member.userId)}`,{method:'PATCH',body:JSON.stringify({role})});byId('manageUsersMessage').textContent=`${name}'s firm role was updated and recorded.`;await loadManageUsers();}catch(error){select.value=previous;select.disabled=false;byId('manageUsersMessage').textContent=error.message;}}
async function setMembershipActive(member,active,button){const name=member.user?.name??member.userId;const prompt=active?`Restore ${name}'s access to this firm?`:`Remove ${name}'s access to this firm? Atlas will sign the user out, preserve the firm history and audit record, and allow an administrator to restore access later.`;if(!window.confirm(prompt))return;button.disabled=true;byId('manageUsersMessage').textContent=active?`Restoring ${name}…`:`Removing ${name}'s firm access and closing active sessions…`;try{const path=`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/memberships/${encodeURIComponent(member.userId)}/${active?'reactivate':'deactivate'}`;await request(path,{method:'POST',body:active?'{}':JSON.stringify({reason:'Firm access removed through Manage Users'})});byId('manageUsersMessage').textContent=active?`${name}'s firm access was restored.`:`${name}'s firm access was removed. Firm history was preserved.`;await loadManageUsers();if(activeView==='settings')await loadSecuritySettings();}catch(error){byId('manageUsersMessage').textContent=error.message;button.disabled=false;}}
function renderFirmInvitations(invitations){const list=byId('invitationList');list.replaceChildren();for(const invitation of invitations.filter(item=>item.status==='pending')){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(memberRoleLabel(invitation.role))} · pending</span><h3>${escape(invitation.email)}</h3><p class="muted">Expires ${escape(readableAccountDate(invitation.expiresAt))}</p>`;const button=document.createElement('button');button.type='button';button.className='danger';button.textContent='Cancel invitation';button.addEventListener('click',()=>void cancelFirmInvitation(invitation,button));card.append(button);list.append(card);}if(!list.children.length)list.innerHTML='<div class="empty">No pending invitations.</div>';}
async function cancelFirmInvitation(invitation,button){if(!window.confirm(`Cancel the pending invitation for ${invitation.email}? The one-time link will stop working.`))return;button.disabled=true;try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/invitations/${encodeURIComponent(invitation.id)}`,{method:'DELETE'});byId('manageUsersMessage').textContent=`The invitation for ${invitation.email} was canceled.`;await loadManageUsers();}catch(error){byId('manageUsersMessage').textContent=error.message;button.disabled=false;}}
async function loadManageUsers(){if(!session)return;const guard=byId('manageUsersGuard');const admin=byId('manageUsersAdmin');guard.classList.remove('hidden');admin.classList.add('hidden');guard.textContent='Confirming administrator access…';let allowed=['owner','admin'].includes(session.workspaceRole);if(!allowed)allowed=await loadAccountAccess();if(!allowed){byId('manageUsersSubscription').textContent='Administrator only';guard.textContent='Manage Users is available only to this firm’s owner and administrators.';return;}try{const [subscription,members,invitations]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/subscription`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/memberships`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/invitations`)]);const current=members.find(item=>item.userId===session.user?.id);if(!applyManageUsersRole(current?.role)){throw new Error('Manage Users is available only to this firm’s owner and administrators.');}const active=members.filter(item=>item.active!==false).length;byId('manageUsersSubscription').textContent=`${subscription.plan} · ${subscription.status} · ${active}/${subscription.seatLimit} seats`;renderFirmMembers(members);renderFirmInvitations(invitations);byId('inviteMemberForm').classList.remove('hidden');byId('inviteError').textContent='';guard.classList.add('hidden');admin.classList.remove('hidden');}catch(error){applyManageUsersRole(null);byId('manageUsersSubscription').textContent='Administrator only';guard.textContent=error.message;}}
async function loadSettings(){return loadManageUsers();}
byId('inviteMemberForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('inviteError').textContent='';byId('invitationLink').classList.add('hidden');try{const invitation=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/invitations`,{method:'POST',body:JSON.stringify({email:byId('inviteEmail').value,role:byId('inviteRole').value})});const link=`${window.location.origin}/?invite=${encodeURIComponent(invitation.invitationToken)}`;const output=byId('invitationLink');output.replaceChildren();const heading=document.createElement('strong');heading.textContent='One-time invitation link';const field=document.createElement('input');field.value=link;field.readOnly=true;field.setAttribute('aria-label','One-time invitation link');field.addEventListener('focus',()=>field.select());const copy=document.createElement('button');copy.type='button';copy.textContent='Copy link';copy.addEventListener('click',async()=>{try{await navigator.clipboard.writeText(link);copy.textContent='Copied';}catch{field.select();copy.textContent='Select and copy the link';}});output.append(heading,field,copy);output.classList.remove('hidden');event.target.reset();await loadManageUsers();}catch(error){byId('inviteError').textContent=error.message;}});
byId('mfaEnrollForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('mfaMessage').textContent='Creating encrypted authenticator enrollment…';try{const enrollment=await request('/v1/auth/mfa/enroll',{method:'POST',body:JSON.stringify({password:byId('mfaPassword').value})});byId('mfaSecret').value=enrollment.secret;byId('mfaRecoveryCodes').value=enrollment.recoveryCodes.join('\n');byId('mfaEnrollment').classList.remove('hidden');byId('mfaMessage').textContent='Save the recovery codes offline. They will not be displayed again.';byId('mfaConfirmCode').focus();}catch(error){byId('mfaMessage').textContent=error.message;}});
