function searchObjectView(object){if(object.dimension==='matter')return'matters';if(isContactObject(object))return'contacts';if(object.dimension==='document')return'documents';if(['incoming_email','email'].includes(object.type))return'email';if(['calendar_event','event'].includes(object.type))return'calendar';if(['legal_research','legal_research_analysis'].includes(object.type))return'legal-research';if(['task','deadline'].includes(object.type))return'tasks';if(['invoice','payment','refund','payment_request','financing_application','bank_transaction','expense','time_entry'].includes(object.type))return'accounting';if(['phone_call','communication','text_message'].includes(object.type))return'communications';return'workspace';}
async function openSearchObject(object){if(object.dimension==='matter'){await openMatter(object);return;}const matter=workspaceMatter(object.parentObjectId??object.state?.matterId);const category=objectCategory(object);if(matter&&['tasks','deadlines','documents','communications','billing','contacts'].includes(category)){await openMatter(matter);renderMatterTab(category);return;}const view=searchObjectView(object);showView(view);if(view==='workspace'){byId('workspaceSearch').value=object.title;renderWorkspaceWork();}}
function atlasSearchDestinations(){const destinations=atlasSearchPages.map(page=>({id:`page-${page.view}`,label:page.label,detail:page.detail,terms:`${page.label} ${page.terms}`,activate:()=>showView(page.view)}));for(const [page,label] of Object.entries(accountingPageLabels))destinations.push({id:`accounting-${page}`,label,detail:'Accounting page',terms:`${label} accounting billing finance`,activate:()=>{showView('accounting');showAccountingPage(page,true);}});for(const object of pilotObjects){if(object.deletedAt||object.dimension==='evidence')continue;const view=searchObjectView(object);const matter=object.dimension==='matter'?object:workspaceMatter(object.parentObjectId??object.state?.matterId);const type=object.dimension==='matter'?'Case':object.type.replaceAll('_',' ');const caseContext=matter&&matter.id!==object.id?` · ${matter.title}`:'';destinations.push({id:`object-${object.id}`,label:object.title,detail:`${type}${caseContext}`,terms:`${object.title} ${object.type} ${object.dimension} ${object.state?.caseNumber??''} ${object.state?.clientName??''} ${matter?.title??''} ${view}`,activate:()=>void openSearchObject(object)});}for(const event of firmEvents){const label=eventName(event);destinations.push({id:`event-${event.id}`,label,detail:'Firm event',terms:`${label} ${eventSearchText(event)}`,activate:()=>{showView('events');byId('firmEventSearch').value=label;renderFirmEvents();}});}const seen=new Set();return destinations.filter(destination=>{const key=normalized(`${destination.label}|${destination.detail}`);if(seen.has(key))return false;seen.add(key);return true;});}
function matchingAtlasDestinations(query){const needle=normalized(query);if(!needle)return[];return atlasSearchDestinations().map(destination=>{const label=normalized(destination.label);const terms=normalized(destination.terms);const words=needle.split(' ').filter(Boolean);if(!words.every(word=>label.includes(word)||terms.includes(word)))return null;const rank=label.startsWith(needle)?0:label.includes(needle)?1:2;return{destination,rank};}).filter(Boolean).sort((left,right)=>left.rank-right.rank||left.destination.label.localeCompare(right.destination.label)).slice(0,8).map(match=>match.destination);}
function enhanceAtlasSearch(input,index){if(input.dataset.atlasAutocomplete==='true')return;input.dataset.atlasAutocomplete='true';input.setAttribute('autocomplete','off');input.setAttribute('aria-autocomplete','list');const host=input.closest('label')??input.parentElement;host.classList.add('atlas-search-host');const popup=document.createElement('div');popup.id=`atlas-search-suggestions-${index}`;popup.className='atlas-search-popup hidden';popup.setAttribute('role','listbox');popup.setAttribute('aria-label','Familiar Atlas destinations');input.setAttribute('aria-controls',popup.id);input.setAttribute('aria-expanded','false');host.append(popup);let activeIndex=-1;const close=()=>{popup.classList.add('hidden');popup.replaceChildren();input.setAttribute('aria-expanded','false');input.removeAttribute('aria-activedescendant');activeIndex=-1;};const activate=(destination)=>{close();destination.activate();};const highlight=(buttons,indexToSelect)=>{activeIndex=indexToSelect;buttons.forEach((button,buttonIndex)=>button.classList.toggle('active',buttonIndex===activeIndex));if(activeIndex>=0){input.setAttribute('aria-activedescendant',buttons[activeIndex].id);buttons[activeIndex].scrollIntoView({block:'nearest'});}else input.removeAttribute('aria-activedescendant');};const render=()=>{const matches=matchingAtlasDestinations(input.value);popup.replaceChildren();activeIndex=-1;if(!matches.length){close();return;}matches.forEach((destination,resultIndex)=>{const button=document.createElement('button');button.id=`${popup.id}-option-${resultIndex}`;button.type='button';button.className='atlas-search-option';button.setAttribute('role','option');const label=document.createElement('strong');label.textContent=destination.label;const detail=document.createElement('small');detail.textContent=destination.detail;button.append(label,detail);button.addEventListener('click',()=>activate(destination));popup.append(button);});popup.classList.remove('hidden');input.setAttribute('aria-expanded','true');};input.addEventListener('input',render);input.addEventListener('focus',()=>{if(input.value.trim())render();});input.addEventListener('keydown',event=>{const buttons=[...popup.querySelectorAll('.atlas-search-option')];if(popup.classList.contains('hidden')||!buttons.length)return;if(event.key==='ArrowDown'){event.preventDefault();highlight(buttons,(activeIndex+1)%buttons.length);}else if(event.key==='ArrowUp'){event.preventDefault();highlight(buttons,(activeIndex<=0?buttons.length:activeIndex)-1);}else if(event.key==='Enter'&&activeIndex>=0){event.preventDefault();activate(matchingAtlasDestinations(input.value)[activeIndex]);}else if(event.key==='Escape'){event.preventDefault();close();}});host.addEventListener('focusout',()=>setTimeout(()=>{if(!host.contains(document.activeElement))close();},0));input._closeAtlasSearch=close;}
function installAtlasSearchAutocomplete(){const style=document.createElement('style');style.textContent='.atlas-search-host{position:relative}.atlas-search-popup{position:absolute;z-index:80;top:calc(100% + 5px);left:0;width:100%;min-width:260px;max-height:330px;overflow-y:auto;padding:6px;border:1px solid #b8c6d8;border-radius:11px;background:white;box-shadow:0 18px 40px #142b4a2b}.atlas-search-option{display:grid;width:100%;gap:3px;padding:10px 11px;border:0;border-radius:8px;text-align:left;background:white;color:var(--navy)}.atlas-search-option strong{font-size:13px}.atlas-search-option small{color:var(--muted);font-size:11px}.atlas-search-option:hover,.atlas-search-option:focus,.atlas-search-option.active{background:#eef3f9;outline:none}@media(max-width:600px){.atlas-search-popup{min-width:100%}}';document.head.append(style);let count=0;const enhanceAll=root=>{if(root.matches?.('input[type="search"]'))enhanceAtlasSearch(root,count++);root.querySelectorAll?.('input[type="search"]:not([data-atlas-autocomplete="true"])').forEach(input=>enhanceAtlasSearch(input,count++));};enhanceAll(document);new MutationObserver(records=>records.forEach(record=>record.addedNodes.forEach(node=>{if(node.nodeType===Node.ELEMENT_NODE)enhanceAll(node);}))).observe(document.body,{childList:true,subtree:true});document.addEventListener('pointerdown',event=>{document.querySelectorAll('input[type="search"][data-atlas-autocomplete="true"]').forEach(input=>{if(!input.closest('.atlas-search-host').contains(event.target))input._closeAtlasSearch?.();});});}
installAtlasSearchAutocomplete();
function resetSignedOutUi(){document.body.classList.remove('atlas-authenticated');session=null;conversationId=null;legalResearchConversationId=null;workspaceActions=[];workspaceAwareness=[];socialState=null;legalResearchProviders=[];legalResearchCapabilityState=null;documentExecutionState=null;executableDocuments=[];emailProviders=[];emailConnections=[];smsState=null;activeMatter=null;activeMatterTab='overview';matterDocumentFiles=[];matterDocumentMessage='';matterCommunicationState=null;matterCommunicationMode=null;matterCommunicationMessage='';matterCommunicationRecipients={call:null,text:null,email:null,meeting:null};clearStoredSession();byId('home').classList.add('hidden');byId('onboarding').classList.add('hidden');byId('login').classList.remove('hidden');byId('feed').replaceChildren();byId('transcript').replaceChildren();byId('workspaceAssistantTranscript').replaceChildren();byId('legalResearchChatTranscript').replaceChildren();byId('twinTranscript').replaceChildren();byId('commandStatus').textContent='';byId('workspaceAssistantStatus').textContent='';byId('legalResearchChatStatus').textContent='';byId('twinStatus').textContent='';}
async function signOut(){const refreshToken=session?.refreshToken;try{if(refreshToken)await fetch(`${session.base}/v1/auth/logout`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({refreshToken})});}finally{resetSignedOutUi();}}
async function restoreStoredSession(){let stored;try{stored=JSON.parse(sessionStorage.getItem(sessionStorageKey)??'null');if(!stored?.token||!stored?.refreshToken||!stored?.workspaceId)return;const base=new URL(stored.base??window.location.origin);if(!['http:','https:'].includes(base.protocol))throw new Error('Invalid stored Atlas origin');session={base:base.origin,token:stored.token,refreshToken:stored.refreshToken,workspaceId:stored.workspaceId,user:stored.user??null,workspaceRole:stored.workspaceRole??null};byId('apiBase').value=session.base;byId('workspaceId').value=session.workspaceId;await enterWorkspace();}catch(error){resetSignedOutUi();byId('loginError').textContent='Your saved Atlas session ended. Sign in again.';}}
