function marketingCard(title,detail,badge){const card=document.createElement('article');card.className='object-card';if(badge){const pill=document.createElement('span');pill.className='pill';pill.textContent=badge;card.append(pill);}const heading=document.createElement('h3');heading.textContent=title;const copy=document.createElement('p');copy.className='muted';copy.textContent=detail;card.append(heading,copy);return card;}
function renderMarketing(){if(!marketingState)return;const sourceList=byId('marketingSourceCatalog');sourceList.replaceChildren();for(const source of marketingState.sourceCatalog){sourceList.append(marketingCard(source.label,source.configured?`${source.startingSource} · Connected aggregate feed`:`${source.startingSource} · Jurisdiction source required`,source.configured?'Connected':'Setup required'));const input=document.querySelector(`[data-marketing-event="${source.eventType}"]`);if(input)input.disabled=!source.configured;}byId('marketingSourceStatus').textContent=marketingState.publicSources.length?`${marketingState.publicSources.length} connected`:'Source setup required';byId('marketingScanSubmit').disabled=!marketingState.publicSources.length;
  const signals=byId('marketingSignals');signals.replaceChildren();const choices=byId('marketingSignalChoices');choices.replaceChildren();for(const signal of marketingState.signals){signals.append(marketingCard(signal.title,`${Number(signal.state.count).toLocaleString()} aggregate events · ${signal.state.sources.join(', ')} · No personal records stored`,'Aggregate signal'));const label=document.createElement('label');const checkbox=document.createElement('input');checkbox.type='checkbox';checkbox.dataset.marketingSignal=signal.id;label.append(checkbox,document.createTextNode(`${signal.title} (${Number(signal.state.count).toLocaleString()})`));choices.append(label);}if(!marketingState.signals.length){signals.innerHTML='<div class="empty">No aggregate public signals have been saved for this firm.</div>';choices.textContent='Refresh an approved public source to create aggregate signals.';}byId('marketingSignalCount').textContent=`${marketingState.signals.length} signals`;
  const providers=byId('marketingAdProviders');providers.replaceChildren();for(const provider of marketingState.adProviders)providers.append(marketingCard(provider.label??provider.name,(provider.channels??[]).map(channel=>marketingChannelLabels[channel]??channel).join(', ')||'No supported channels',provider.connected===false?'Setup required':'Connected'));if(!marketingState.adProviders.length)providers.innerHTML='<div class="empty">Connect an approved advertising account before preparing external campaigns. Atlas will still save internal campaign drafts.</div>';
  const campaigns=byId('marketingCampaigns');campaigns.replaceChildren();for(const campaign of marketingState.campaigns){const card=marketingCard(campaign.title,`${campaign.state.practiceArea} · ${campaign.state.channels.map(channel=>marketingChannelLabels[channel]??channel).join(', ')} · $${(campaign.state.budgetMinor/100).toFixed(2)} · ${campaign.state.targeting.geography}`,campaign.state.status.replaceAll('_',' '));const creative=document.createElement('p');creative.textContent=`${campaign.state.creative.headline} — ${campaign.state.creative.body}`;card.append(creative);if(campaign.state.status==='draft'){const review=document.createElement('div');review.className='marketing-review';for(const [key,labelText] of [['attorneyAdvertisingRulesReviewed','I reviewed applicable attorney-advertising and solicitation rules.'],['platformPoliciesReviewed','I reviewed the advertising platforms’ current policies.'],['landingPageReviewed','I reviewed the landing page and required disclaimers.']]){const label=document.createElement('label');const input=document.createElement('input');input.type='checkbox';input.dataset.marketingReview=key;label.append(input,document.createTextNode(labelText));review.append(label);}const prepare=document.createElement('button');prepare.type='button';prepare.textContent='Prepare paused provider campaign';prepare.disabled=!marketingState.adProviders.length;prepare.addEventListener('click',()=>void prepareMarketingCampaign(campaign,card,review,prepare));card.append(review,prepare);}const launches=marketingState.launches.filter(item=>item.state.campaignId===campaign.id);for(const launch of launches){const note=document.createElement('p');note.className='muted';note.textContent=`${launch.state.provider} · ${launch.state.status} · Created paused`;card.append(note);const url=safeExternalUrl(launch.state.managementUrl);if(url){const link=document.createElement('a');link.href=url;link.target='_blank';link.rel='noopener noreferrer';link.textContent='Review in advertising provider';card.append(link);}}campaigns.append(card);}if(!marketingState.campaigns.length)campaigns.innerHTML='<div class="empty">No campaigns have been created.</div>';byId('marketingCampaignCount').textContent=`${marketingState.campaigns.length} campaigns`;
}
async function loadMarketing(){try{marketingState=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/marketing`);renderMarketing();}catch(error){byId('marketingSourceStatus').textContent='Unavailable';byId('marketingCampaignError').textContent=error.message;}}
async function submitMarketingScan(){const button=byId('marketingScanSubmit');button.disabled=true;byId('marketingScanError').textContent='';try{const eventTypes=[...document.querySelectorAll('[data-marketing-event]:checked')].map(input=>input.dataset.marketingEvent);if(!eventTypes.length)throw new Error('Choose at least one connected aggregate event type.');await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/marketing/public-scans`,{method:'POST',body:JSON.stringify({eventTypes,jurisdiction:byId('marketingJurisdiction').value,from:byId('marketingScanFrom').value,to:byId('marketingScanTo').value})});await loadPilotData();await loadMarketing();}catch(error){byId('marketingScanError').textContent=error.message;}finally{button.disabled=!marketingState?.publicSources?.length;}}
async function submitMarketingCampaign(){const button=byId('marketingCampaignForm').querySelector('button[type="submit"]');button.disabled=true;byId('marketingCampaignError').textContent='';try{const selectedChannels=[...document.querySelectorAll('[data-marketing-channel]:checked')].map(input=>input.dataset.marketingChannel);if(!selectedChannels.length)throw new Error('Choose at least one advertising channel.');const sourceSignalIds=[...document.querySelectorAll('[data-marketing-signal]:checked')].map(input=>input.dataset.marketingSignal);await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/marketing/campaigns`,{method:'POST',body:JSON.stringify({title:byId('marketingTitle').value,practiceArea:byId('marketingPracticeArea').value,channels:selectedChannels,budgetMinor:Math.round(Number(byId('marketingBudget').value)*100),startAt:byId('marketingStart').value,endAt:byId('marketingEnd').value,geography:byId('marketingGeography').value,radiusMiles:Number(byId('marketingRadius').value),headline:byId('marketingHeadline').value,body:byId('marketingBody').value,callToAction:byId('marketingCallToAction').value,landingPage:byId('marketingLandingPage').value,sourceSignalIds})});byId('marketingCampaignForm').reset();await loadPilotData();await loadMarketing();}catch(error){byId('marketingCampaignError').textContent=error.message;}finally{button.disabled=false;}}
async function prepareMarketingCampaign(campaign,card,review,button){const values=Object.fromEntries([...review.querySelectorAll('[data-marketing-review]')].map(input=>[input.dataset.marketingReview,input.checked]));if(Object.values(values).some(value=>!value)){const error=document.createElement('p');error.className='error';error.textContent='Complete all three reviews before creating anything with an advertising provider.';card.append(error);return;}button.disabled=true;try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/marketing/campaigns/${encodeURIComponent(campaign.id)}/prepare`,{method:'POST',body:JSON.stringify(values)});await loadPilotData();await loadMarketing();}catch(error){const message=document.createElement('p');message.className='error';message.textContent=error.message;card.append(message);button.disabled=false;}}
