function caseActionKey(tab,matterId=activeMatter?.id){return`${matterId}:${tab}`;}
function caseActionIsoDate(value){if(!value)return null;const date=new Date(value);if(Number.isNaN(date.getTime()))throw new Error('Enter a valid date and time.');return date.toISOString();}
function caseActionMoney(value,label){const amount=Number(value);if(!Number.isFinite(amount)||amount<=0)throw new Error(`${label} must be greater than zero.`);return Math.round(amount*100);}
