function caseTaskChatState(matterId){if(!caseTaskChatStates.has(matterId))caseTaskChatStates.set(matterId,{conversationId:null,user:null,answer:null,sources:[],actionProposals:[],status:'ready',error:null});return caseTaskChatStates.get(matterId);}
function renderCaseTaskExchange(host,state){host.replaceChildren();if(!state.user&&!state.answer&&!state.error)return;host.classList.remove('hidden');if(state.user){const user=document.createElement('article');user.className='message user';const heading=document.createElement('header');heading.textContent='You';const body=document.createElement('div');appendCaseLinkedText(body,state.user);user.append(heading,body);host.append(user);}const atlas=document.createElement('article');atlas.className='message atlas';const heading=document.createElement('header');heading.textContent='Atlas · this case';const body=document.createElement('div');if(state.status==='working')body.textContent='Reviewing this case’s canonical tasks, documents, communications, deadlines, billing, and accepted intelligence…';else appendCaseLinkedText(body,state.error?`I could not complete that request: ${state.error}`:state.answer??'');atlas.append(heading,body);if(state.actionProposals?.length){const label=document.createElement('strong');label.textContent='Reviewable work prepared';const actions=document.createElement('div');actions.className='actions';state.actionProposals.forEach(action=>actions.append(renderAction(action)));atlas.append(label,actions);}if(state.sources?.length){const sources=document.createElement('p');sources.className='muted';sources.textContent=`Grounded in ${state.sources.length} authorized Atlas record${state.sources.length===1?'':'s'}.`;atlas.append(sources);}host.append(atlas);}
function renderCaseTaskSuggestions(host,matterId){host.replaceChildren();const currentIds=new Set((caseTaskChatState(matterId).actionProposals??[]).map(action=>action.id));const suggestions=workspaceActions.filter(action=>action.actionType==='create_task'&&action.status==='pending'&&action.input?.matterId===matterId&&!currentIds.has(action.id));for(const action of suggestions)host.append(renderAction(action));if(!suggestions.length)host.innerHTML='<div class="empty">No additional Atlas-identified tasks are awaiting review for this case.</div>';}
function renderCaseTaskAssistant(panel){const matter=activeMatter;if(!matter)return;const state=caseTaskChatState(matter.id);const section=document.createElement('section');section.className='case-task-assistant';section.innerHTML='<div class="section-head"><div><span class="pill">Atlas · case task workspace</span><h3>What do you need?</h3></div><span class="command-console-badge">This case only</span></div><p class="muted">Ask Atlas to explain, create, prioritize, or perform work for this case. Atlas reads the complete canonical case context; consequential work remains reviewable and nothing is sent or filed automatically.</p><div class="case-task-exchange hidden" data-case-task-exchange aria-live="polite"></div><form class="case-task-chat-form" data-case-task-chat><label><span class="sr-only">Ask or request anything for this case</span><textarea name="prompt" required maxlength="12000" placeholder="Ask or request anything for this case…"></textarea></label><button class="primary" type="submit">Ask Atlas</button></form><p class="muted" data-case-task-chat-status role="status"></p><div class="case-task-suggestions"><div class="section-head"><h3>Atlas-identified tasks awaiting review</h3></div><div class="object-grid" data-case-task-suggestions></div></div>';const exchange=section.querySelector('[data-case-task-exchange]');renderCaseTaskExchange(exchange,state);const form=section.querySelector('[data-case-task-chat]');const textarea=form.querySelector('textarea');form.addEventListener('submit',event=>void submitCaseTaskChat(event,matter.id));textarea.addEventListener('keydown',event=>{if(event.key==='Enter'&&!event.shiftKey&&!event.isComposing){event.preventDefault();form.requestSubmit();}});if(state.status==='working'){textarea.disabled=true;form.querySelector('button').disabled=true;section.querySelector('[data-case-task-chat-status]').textContent='Atlas is working in this case…';}renderCaseTaskSuggestions(section.querySelector('[data-case-task-suggestions]'),matter.id);panel.querySelector('[data-case-action-form]').before(section);}
async function submitCaseTaskChat(event,matterId){event.preventDefault();const form=event.currentTarget;const textarea=form.querySelector('textarea');const prompt=textarea.value.trim();if(!prompt)return;const matter=activeMatter;if(!matter||matter.id!==matterId)return;const state=caseTaskChatState(matterId);state.user=prompt;state.answer=null;state.error=null;state.sources=[];state.actionProposals=[];state.status='working';renderMatterTab('tasks');try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/assistant/query`,{method:'POST',body:JSON.stringify({prompt,contextObjectId:matterId,...(state.conversationId?{conversationId:state.conversationId}:{})})});state.conversationId=result.conversationId??state.conversationId;state.answer=result.answer;state.sources=result.sources??[];state.actionProposals=result.actionProposals??[];state.status='ready';await loadPilotData();if(activeMatter?.id===matterId&&activeMatterTab==='tasks')renderMatterTab('tasks');}catch(error){state.error=error.message;state.status='ready';if(activeMatter?.id===matterId&&activeMatterTab==='tasks')renderMatterTab('tasks');}}
function renderCaseActionResult(panel,result){const host=panel.querySelector('[data-case-atlas-result]');host.replaceChildren();if(!result)return;host.classList.remove('hidden');const message=document.createElement('p');message.className=result.error?'error':'muted';appendCaseLinkedText(message,result.error??result.message??result.answer??'Case action completed.');host.append(message);if(result.actionProposals?.length){const heading=document.createElement('strong');heading.textContent='Prepared for attorney review';const actions=document.createElement('div');actions.className='actions';result.actionProposals.forEach(action=>actions.append(renderAction(action)));host.append(heading,actions);}if(result.sources?.length){const sourceCount=document.createElement('p');sourceCount.className='muted';sourceCount.textContent=`Grounded in ${result.sources.length} authorized Atlas record${result.sources.length===1?'':'s'}.`;host.append(sourceCount);}}
