function installEditableAccountProfiles(){const page=document.querySelector('[data-account-page="profile"]');page.innerHTML='<div class="section-head"><div><span class="pill">Reusable Atlas identity</span><h2>Firm &amp; attorney information</h2></div><span id="accountProfileAccess" class="command-console-badge">Loading</span></div><p class="muted">Save professional information once. Atlas can then use it throughout this firm’s demo for document drafts, communications, billing, case work, search, and AI context.</p><form id="accountProfileEditor"><section class="account-profile-section"><div class="section-head"><div><span class="pill">Attorney information</span><h3>My professional profile</h3></div></div><div class="grid"><label>Name<input id="accountProfileName" name="attorneyName" required maxlength="240" autocomplete="name"></label><label>Sign-in email<input id="accountProfileEmail" name="signInEmail" type="email" readonly></label><label>Professional email<input name="professionalEmail" type="email" maxlength="320" autocomplete="email"></label><label>Professional title<input name="title" maxlength="160" placeholder="Partner, associate, counsel…"></label><label>Office phone<input name="attorneyPhone" maxlength="80" autocomplete="tel"></label><label>Mobile phone<input name="mobilePhone" maxlength="80" autocomplete="tel"></label><label>Bar number<input name="barNumber" maxlength="120"></label><label>Bar jurisdictions<input name="barJurisdictions" maxlength="1000" placeholder="Florida, U.S. District Court…"></label><label>Practice areas<input name="attorneyPracticeAreas" maxlength="1000" placeholder="Civil litigation, family law…"></label></div><label>Professional biography<textarea name="bio" maxlength="4000" placeholder="Professional background for firm materials and drafts…"></textarea></label><label>Default signature block<textarea name="signatureBlock" maxlength="4000" placeholder="Name, title, firm, phone, email…"></textarea></label></section><section class="account-profile-section"><div class="section-head"><div><span class="pill">Firm information</span><h3>Firm profile</h3></div><span class="muted" id="firmProfilePermission"></span></div><fieldset id="firmProfileFields"><div class="grid"><label>Display name<input name="firmDisplayName" required maxlength="240" autocomplete="organization"></label><label>Legal name<input name="firmLegalName" maxlength="240"></label><label>General email<input name="firmEmail" type="email" maxlength="320"></label><label>Main phone<input name="firmPhone" maxlength="80"></label><label>Website<input name="firmWebsite" type="url" maxlength="1000" placeholder="https://"></label><label>Address line 1<input name="addressLine1" maxlength="240" autocomplete="address-line1"></label><label>Address line 2<input name="addressLine2" maxlength="240" autocomplete="address-line2"></label><label>City<input name="city" maxlength="120" autocomplete="address-level2"></label><label>State or province<input name="state" maxlength="120" autocomplete="address-level1"></label><label>Postal code<input name="postalCode" maxlength="40" autocomplete="postal-code"></label><label>Country<input name="country" maxlength="120" autocomplete="country-name"></label><label>Jurisdictions served<input name="firmJurisdictions" maxlength="1000" placeholder="Florida, federal courts…"></label><label>Practice areas<input name="firmPracticeAreas" maxlength="1000" placeholder="Criminal defense, civil litigation…"></label></div></fieldset></section><div class="account-profile-save"><button id="saveAccountProfiles" class="primary" type="submit">Save firm &amp; attorney information</button><p id="accountProfileStatus" class="muted" role="status"></p></div></form>';const style=document.createElement('style');style.textContent='.account-profile-section{padding:18px 0;border-top:1px solid var(--line)}.account-profile-section:first-of-type{margin-top:16px}.account-profile-section h3{font:21px Georgia,serif;margin:4px 0}.account-profile-section textarea{min-height:96px}.account-profile-section fieldset{border:0;margin:0;padding:0;min-width:0}.account-profile-section fieldset:disabled{opacity:.68}.account-profile-save{position:sticky;bottom:0;display:flex;align-items:center;gap:14px;padding:14px 0;background:linear-gradient(transparent,#fff 22%)}.account-profile-save p{margin:0}';document.head.append(style);byId('accountProfileEditor').addEventListener('submit',event=>void saveAccountProfiles(event));}installEditableAccountProfiles();
function accountProfileList(value){return Array.isArray(value)?value.join(', '):'';}
function setAccountProfileValue(name,value){const field=byId('accountProfileEditor').elements.namedItem(name);if(field)field.value=value??'';}
function renderEditableAccountProfiles(profile){accountProfileSnapshot=profile;const attorney=profile.attorney?.state??{};const firm=profile.firm?.state??{};renderAccountProfile({name:attorney.name??profile.identity.name,email:profile.identity.email});setAccountProfileValue('professionalEmail',attorney.professionalEmail);setAccountProfileValue('title',attorney.title);setAccountProfileValue('attorneyPhone',attorney.phone);setAccountProfileValue('mobilePhone',attorney.mobilePhone);setAccountProfileValue('barNumber',attorney.barNumber);setAccountProfileValue('barJurisdictions',accountProfileList(attorney.barJurisdictions));setAccountProfileValue('attorneyPracticeAreas',accountProfileList(attorney.practiceAreas));setAccountProfileValue('bio',attorney.bio);setAccountProfileValue('signatureBlock',attorney.signatureBlock);setAccountProfileValue('firmDisplayName',firm.displayName??profile.firm?.title);setAccountProfileValue('firmLegalName',firm.legalName);setAccountProfileValue('firmEmail',firm.generalEmail);setAccountProfileValue('firmPhone',firm.phone);setAccountProfileValue('firmWebsite',firm.website);for(const field of ['addressLine1','addressLine2','city','state','postalCode','country'])setAccountProfileValue(field,firm[field]);setAccountProfileValue('firmJurisdictions',accountProfileList(firm.jurisdictions));setAccountProfileValue('firmPracticeAreas',accountProfileList(firm.practiceAreas));byId('firmProfileFields').disabled=!profile.canEditFirm;byId('firmProfilePermission').textContent=profile.canEditFirm?'Owner/admin editable':'Owner or administrator only';byId('accountProfileAccess').textContent=profile.role??'Firm member';byId('saveAccountProfiles').disabled=profile.role==='viewer';byId('saveAccountProfiles').textContent=profile.canEditFirm?'Save firm & attorney information':'Save attorney information';if(firm.displayName)byId('firmName').textContent=firm.displayName;}
async function loadEditableAccountProfiles(){if(!session)return;byId('accountProfileStatus').textContent='Loading saved firm and attorney information…';try{const profile=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/account-profile`);renderEditableAccountProfiles(profile);byId('accountProfileStatus').textContent='Saved profile information is available throughout this firm’s Atlas workspace.';}catch(error){byId('accountProfileStatus').textContent=error.message;}}
function profileListInput(form,name){return String(new FormData(form).get(name)??'').split(',').map(item=>item.trim()).filter(Boolean);}
async function saveAccountProfiles(event){event.preventDefault();const form=event.currentTarget;const data=new FormData(form);const button=byId('saveAccountProfiles');button.disabled=true;byId('accountProfileStatus').textContent='Saving canonical firm and attorney profiles…';const payload={attorney:{name:String(data.get('attorneyName')).trim(),professionalEmail:String(data.get('professionalEmail')).trim()||null,title:String(data.get('title')).trim()||null,phone:String(data.get('attorneyPhone')).trim()||null,mobilePhone:String(data.get('mobilePhone')).trim()||null,barNumber:String(data.get('barNumber')).trim()||null,barJurisdictions:profileListInput(form,'barJurisdictions'),practiceAreas:profileListInput(form,'attorneyPracticeAreas'),bio:String(data.get('bio')).trim()||null,signatureBlock:String(data.get('signatureBlock')).trim()||null}};if(accountProfileSnapshot?.canEditFirm)payload.firm={displayName:String(data.get('firmDisplayName')).trim(),legalName:String(data.get('firmLegalName')).trim()||null,generalEmail:String(data.get('firmEmail')).trim()||null,phone:String(data.get('firmPhone')).trim()||null,website:String(data.get('firmWebsite')).trim()||null,addressLine1:String(data.get('addressLine1')).trim()||null,addressLine2:String(data.get('addressLine2')).trim()||null,city:String(data.get('city')).trim()||null,state:String(data.get('state')).trim()||null,postalCode:String(data.get('postalCode')).trim()||null,country:String(data.get('country')).trim()||null,jurisdictions:profileListInput(form,'firmJurisdictions'),practiceAreas:profileListInput(form,'firmPracticeAreas')};try{const profile=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/account-profile`,{method:'PATCH',body:JSON.stringify(payload)});renderEditableAccountProfiles(profile);await loadPilotData();byId('accountProfileStatus').textContent='Saved. Atlas can now use this information throughout the demo.';}catch(error){byId('accountProfileStatus').textContent=error.message;}finally{button.disabled=accountProfileSnapshot?.role==='viewer';}}
